import React, { useState, useMemo, useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import { ChevronRight, ShoppingCart, Star, Info, Shield, Truck } from "lucide-react";
import { useQuery } from "convex/react";
import { api } from "../../convex/_generated/api";
import { useCart } from "../context/CartContext.jsx";
import { formatPrice } from "../utils/format.js";
import Button from "../components/ui/Button";
import LoadingSpinner from "../components/ui/LoadingSpinner";

export default function ProductDetails() {
    const { id } = useParams();
    const { addItem } = useCart();

    const product = useQuery(api.products.getById, id ? { id } : "skip");

    const [mainImage, setMainImage] = useState(null);
    const [selectedColor, setSelectedColor] = useState(null);
    const [selectedSize, setSelectedSize] = useState(null);
    const [selectedLogo, setSelectedLogo] = useState(null);
    const [quantity, setQuantity] = useState(1);
    const [logoPreview, setLogoPreview] = useState(null);

    // Scroll to top when navigating to product details
    useEffect(() => {
        window.scrollTo(0, 0);
    }, [id]);

    // Initialize state when product is loaded
    useEffect(() => {
        if (product) {
            setMainImage(product.image);
            setSelectedColor(product.colors?.[0] || null);
            setSelectedSize(product.sizes?.[0] || null);
            setSelectedLogo(product.logos?.[0] || null);
        }
    }, [product]);

    // Update main image when color selection changes (color-only variant images)
    useEffect(() => {
        if (product?.logoImages && selectedColor?.name) {
            // Look under _default key first, then fall back to any key that has this color
            const colorImages = product.logoImages["_default"]?.[selectedColor.name]
                || Object.values(product.logoImages).find(
                    colorMap => colorMap?.[selectedColor.name]?.length > 0
                )?.[selectedColor.name];
            if (colorImages && colorImages.length > 0) {
                setMainImage(colorImages[0]);
                return;
            }
        }
        if (product) {
            setMainImage(product.image);
        }
    }, [selectedColor, product]);

    // Get variant-specific images based on selected color only
    const getVariantImages = () => {
        if (product?.logoImages && selectedColor?.name) {
            const colorImages = product.logoImages["_default"]?.[selectedColor.name]
                || Object.values(product.logoImages).find(
                    colorMap => colorMap?.[selectedColor.name]?.length > 0
                )?.[selectedColor.name];
            if (colorImages && colorImages.length > 0) {
                return colorImages;
            }
        }
        return product.images || [product.image];
    };

    // Show loading spinner while Convex query is loading
    if (product === undefined) {
        return (
            <div className="min-h-screen flex items-center justify-center">
                <LoadingSpinner size="lg" />
            </div>
        );
    }

    if (!product) {
        return (
            <div className="max-w-7xl mx-auto px-4 py-32 text-center animate-in fade-in duration-700">
                <div className="inline-flex items-center justify-center w-24 h-24 rounded-full bg-gray-50 mb-8">
                    <Info size={40} className="text-gray-300" />
                </div>
                <h2 className="text-[var(--text-3xl)] font-black text-brand-navy tracking-tight mb-4">Product not found</h2>
                <p className="text-gray-500 mb-10 max-w-md mx-auto">This item may have been moved or is currently unavailable in your region.</p>
                <Link to="/shop">
                    <Button variant="secondary" size="md">Return to Shop</Button>
                </Link>
            </div>
        );
    }

    // Better gallery handling - now includes logo variant images
    const gallery = getVariantImages();

    return (
        <div className="bg-white min-h-screen overflow-x-hidden">
            {/* Breadcrumbs */}
            <div className="bg-gray-50/50 border-b border-gray-100">
                <nav className="max-w-7xl mx-auto px-4 py-4 flex items-center text-[10px] font-bold uppercase tracking-widest text-gray-400">
                    <Link to="/" className="hover:text-brand-orange transition-colors">Home</Link>
                    <ChevronRight size={10} className="mx-3 text-gray-300" />
                    <Link to="/shop" className="hover:text-brand-orange transition-colors">Shop</Link>
                    <ChevronRight size={10} className="mx-3 text-gray-300" />
                    <span className="text-gray-900 truncate">{product.name}</span>
                </nav>
            </div>

            <main className="max-w-7xl mx-auto px-4 py-12 sm:py-24 grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-20">
                {/* Left: Image Gallery (Span 7) */}
                <div className="lg:col-span-5 space-y-4 sm:space-y-6">
                    <div className="relative aspect-[3/4] sm:aspect-[4/5] rounded-2xl sm:rounded-[2rem] overflow-hidden bg-gray-50/50 premium-shadow border border-gray-100 animate-in fade-in zoom-in-95 duration-700">
                        <img
                            src={mainImage || product.image}
                            alt={product.name}
                            className="w-full h-full object-cover transition-all duration-700 ease-in-out hover:scale-110"
                        />
                        {/* Temporary logo preview overlay */}
                        {logoPreview && (
                            <div
                                className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-sm z-10 animate-in fade-in duration-300 cursor-pointer"
                                onClick={() => setLogoPreview(null)}
                            >
                                <div className="bg-white rounded-2xl p-4 shadow-2xl animate-in zoom-in-95 duration-300 max-w-[70%]">
                                    <img src={logoPreview} alt="Logo preview" className="w-full object-contain rounded-xl" />
                                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest text-center mt-3">Logo Preview</p>
                                </div>
                            </div>
                        )}
                    </div>
                    <div className="flex gap-2 sm:gap-4 overflow-x-auto py-2 sm:py-4 scrollbar-hide px-1 sm:px-2">
                        {gallery.map((img, idx) => (
                            <button
                                key={idx}
                                onClick={() => setMainImage(img)}
                                className={`flex-shrink-0 w-16 h-20 sm:w-24 sm:h-28 rounded-xl sm:rounded-2xl overflow-hidden border-2 transition-all duration-300 interactive-scale ${mainImage === img
                                    ? "border-brand-orange shadow-lg scale-105"
                                    : "border-transparent opacity-60 grayscale-[50%]"
                                    }`}
                            >
                                <img src={img} alt="" className="w-full h-full object-cover" />
                            </button>
                        ))}
                    </div>
                </div>

                {/* Right: Info & Actions (Span 5) */}
                <div className="lg:col-span-7 flex flex-col pt-4">
                    <div className="mb-10 animate-in slide-in-from-right-10 duration-700 delay-100">
                        {product.badge && (
                            <span className="inline-block px-4 py-1.5 rounded-full bg-orange-100 text-brand-orange text-[10px] font-black uppercase tracking-[0.2em] mb-6 shadow-sm">
                                {product.badge}
                            </span>
                        )}
                        <h1 className="text-[var(--text-4xl)] font-black text-brand-navy leading-tight tracking-tighter mb-2">
                            {product.name}
                        </h1>
                        {product.type && (
                            <p className="text-sm font-bold text-brand-orange uppercase tracking-widest mb-6">
                                {product.type} Edition
                            </p>
                        )}
                        <div className="flex items-center gap-6">
                            <span className="text-3xl font-black text-brand-orange tracking-tight">
                                {formatPrice(product.price)}
                            </span>
                            <div className="h-6 w-[1px] bg-gray-200" />
                            <div className="flex items-center gap-1.5 px-3 py-1.5 bg-yellow-50 rounded-lg">
                                <Star size={16} fill="#fbbf24" className="text-yellow-400" />
                                <span className="text-sm font-black text-gray-800">{product.rating}</span>
                                <span className="text-gray-400 text-xs font-bold pl-1 border-l border-yellow-200 ml-1">124 Reviews</span>
                            </div>
                        </div>
                    </div>

                    <p className="text-gray-500 text-lg leading-relaxed mb-10 font-medium">
                        {product.description || "Inspired by campus life, this DAUST essential combines comfort with university spirit. Perfect for everyday wear or as a special gift."}
                    </p>

                    {/* Variants Section */}
                    <div className="space-y-10 mb-12 animate-in slide-in-from-right-10 duration-700 delay-200">
                        {/* Logo Variants - click to preview */}
                        {product.logos && product.logos.length > 0 && (
                            <div>
                                <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-5">
                                    Logo Style ┬╖ <span className="text-brand-navy">{selectedLogo?.name || "Select"}</span>
                                </h3>
                                <div className="flex flex-wrap gap-3">
                                    {product.logos.map((logo) => (
                                        <button
                                            key={logo.id || logo.name}
                                            onClick={() => {
                                                setSelectedLogo(logo);
                                                if (logo.image) {
                                                    setLogoPreview(logo.image);
                                                    setTimeout(() => setLogoPreview(null), 2500);
                                                }
                                            }}
                                            className={`flex items-center gap-2 px-4 py-2.5 rounded-xl font-black text-sm transition-all duration-300 border-2 interactive-scale ${selectedLogo?.id === logo.id || selectedLogo?.name === logo.name
                                                    ? "border-brand-navy bg-brand-navy text-white shadow-xl shadow-brand-navy/20"
                                                    : "border-gray-100 text-gray-500 hover:border-brand-navy hover:text-brand-navy"
                                                }`}
                                        >
                                            {logo.image && (
                                                <img src={logo.image} alt={logo.name} className="w-7 h-7 rounded-lg object-cover" />
                                            )}
                                            {logo.name}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Colors */}
                        {product.colors && product.colors.length > 0 && (
                            <div>
                                <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] mb-5">
                                    Select Color ┬╖ <span className="text-brand-navy">{selectedColor?.name}</span>
                                </h3>
                                <div className="flex gap-4">
                                    {product.colors.map((color) => (
                                        <button
                                            key={color.name}
                                            onClick={() => setSelectedColor(color)}
                                            className={`relative w-12 h-12 rounded-full ring-2 ring-offset-4 transition-all duration-300 interactive-scale ${selectedColor?.name === color.name
                                                ? "ring-brand-orange"
                                                : "ring-transparent"
                                                }`}
                                        >
                                            <span
                                                className="block w-full h-full rounded-full shadow-inner border border-black/5"
                                                style={{ backgroundColor: color.hex }}
                                            />
                                            {selectedColor?.name === color.name && (
                                                <span className="absolute inset-0 flex items-center justify-center">
                                                    <svg className="w-5 h-5 text-white drop-shadow-md" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                                                    </svg>
                                                </span>
                                            )}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}

                        {/* Sizes */}
                        {product.sizes && product.sizes.length > 0 && (
                            <div>
                                <div className="flex justify-between items-center mb-5">
                                    <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Select Your Size</h3>
                                    <button className="text-[10px] text-brand-orange font-black uppercase tracking-widest hover:underline">Size Guide</button>
                                </div>
                                <div className="flex flex-wrap gap-3">
                                    {product.sizes.map((size) => (
                                        <button
                                            key={size}
                                            onClick={() => setSelectedSize(size)}
                                            className={`min-w-[70px] h-14 rounded-xl font-black text-sm transition-all duration-300 border-2 interactive-scale ${selectedSize === size
                                                ? "border-brand-navy bg-brand-navy text-white shadow-xl shadow-brand-navy/20"
                                                : "border-gray-100 text-gray-500 hover:border-brand-navy hover:text-brand-navy"
                                                }`}
                                        >
                                            {size}
                                        </button>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Add to Cart Actions */}
                    <div className="mt-auto pt-10 border-t border-gray-100 animate-in slide-in-from-bottom-5 duration-700 delay-300">
                        <div className="flex flex-wrap gap-4 items-center">
                            {/* Stock Status */}
                            <div className="w-full mb-4">
                                <div className="flex items-center gap-2">
                                    <div className={`w-2 h-2 rounded-full ${product.stock === 0 ? "bg-red-500" : product.stock <= 5 ? "bg-orange-500" : "bg-green-500"}`} />
                                    <span className={`text-[10px] font-black uppercase tracking-widest ${product.stock === 0 ? "text-red-500" : product.stock <= 5 ? "text-orange-500" : "text-green-500"}`}>
                                        {product.stock === 0 ? "Currently Out of Stock" : product.stock <= 5 ? `Low Stock: Only ${product.stock} Left` : "In Stock & Ready to Ship"}
                                    </span>
                                </div>
                            </div>

                            {/* Quantity Selector */}
                            <div className={`flex items-center bg-gray-50 rounded-2xl p-1 h-16 w-full sm:w-auto ${product.stock === 0 ? "opacity-50 pointer-events-none" : ""}`}>
                                <button
                                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                                    className="w-12 h-full rounded-xl hover:bg-white hover:shadow-sm text-xl font-bold transition-all"
                                    disabled={product.stock === 0}
                                >
                                    ΓêÆ
                                </button>
                                <span className="w-14 text-center font-black text-brand-navy">{quantity}</span>
                                <button
                                    onClick={() => setQuantity(q => Math.min(product.stock || 99, q + 1))}
                                    className="w-12 h-full rounded-xl hover:bg-white hover:shadow-sm text-xl font-bold transition-all"
                                    disabled={product.stock === 0}
                                >
                                    +
                                </button>
                            </div>

                            {/* Add to Cart Button */}
                            <Button
                                variant={product.stock === 0 ? "secondary" : "primary"}
                                size="lg"
                                uppercase={false}
                                className={`flex-1 h-16 rounded-2xl gap-4 shadow-xl shadow-brand-navy/10 group normal-case min-w-[200px] transition-all ${product.stock === 0 ? "opacity-50 cursor-not-allowed" : "hover:-translate-y-0.5 hover:shadow-brand-orange/20"}`}
                                disabled={product.stock === 0}
                                onClick={() => {
                                    if (product.stock === 0) return;

                                    // Validate selections
                                    if (product.colors?.length > 0 && !selectedColor) {
                                        alert('Please select a color');
                                        return;
                                    }
                                    if (product.sizes?.length > 0 && !selectedSize) {
                                        alert('Please select a size');
                                        return;
                                    }
                                    if (product.logos?.length > 0 && !selectedLogo) {
                                        alert('Please select a logo style');
                                        return;
                                    }

                                    addItem({
                                        ...product,
                                        image: mainImage || product.image,
                                        selectedColor: selectedColor?.name,
                                        selectedSize: selectedSize,
                                        selectedLogo: selectedLogo?.name
                                    }, quantity);
                                }}
                            >
                                {product.stock === 0 ? (
                                    <span className="text-base">Sold Out</span>
                                ) : (
                                    <>
                                        <ShoppingCart size={22} className="group-hover:rotate-12 transition-transform" />
                                        <span className="text-base">Add to Shopping Bag</span>
                                    </>
                                )}
                            </Button>

                        </div>

                        {/* Trust Badges */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mt-8 sm:mt-12 bg-gray-50/50 p-4 sm:p-6 rounded-2xl sm:rounded-3xl">
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-white rounded-xl shadow-sm">
                                    <Truck size={20} className="text-brand-orange" />
                                </div>
                                <div>
                                    <p className="text-[10px] font-black uppercase text-gray-900 leading-none">Fast Delivery</p>
                                    <p className="text-[10px] text-gray-500 mt-1">2-4 days campus ship</p>
                                </div>
                            </div>
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-white rounded-xl shadow-sm">
                                    <Shield size={20} className="text-green-500" />
                                </div>
                                <div>
                                    <p className="text-[10px] font-black uppercase text-gray-900 leading-none">Secure Payment</p>
                                    <p className="text-[10px] text-gray-500 mt-1">100% encrypted</p>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </main>

            {/* Product Details Tabs */}
            <section className="max-w-7xl mx-auto px-4 py-24 sm:py-32 border-t border-gray-100">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-16">
                    <div>
                        <h4 className="font-black text-brand-navy mb-5 uppercase tracking-[0.2em] text-[10px]">Premium Materials</h4>
                        <p className="text-gray-500 text-sm italic leading-relaxed">"Every fiber is selected to endure the rigorous yet rewarding lifestyle of the DAUST student. We prioritize organic cotton and high-density blends for maximum longevity."</p>
                    </div>
                    <div>
                        <h4 className="font-black text-brand-navy mb-5 uppercase tracking-[0.2em] text-[10px]">Our Promise</h4>
                        <p className="text-gray-500 text-sm leading-relaxed">Part of our "Excellence in Gear" initiativeΓÇöresponsibly manufactured to ensure that your university pride never comes at a cost to the community or planet.</p>
                    </div>
                    <div>
                        <h4 className="font-black text-brand-navy mb-5 uppercase tracking-[0.2em] text-[10px]">Exchanges</h4>
                        <p className="text-gray-500 text-sm leading-relaxed">Not the perfect fit? Campus exchanges are always free. External returns accepted within 14 days of receipt in original condition.</p>
                    </div>
                </div>
            </section>
        </div>
    );
}

import React, { useState, useMemo, useEffect } from "react";
import { useQuery } from "convex/react";
import { useLocation } from "react-router-dom";
import { api } from "../../convex/_generated/api";
import ProductCard from "../components/ProductCard.jsx";
import ProductSetCard from "../components/ProductSetCard.jsx";
import Newsletter from "../components/Newsletter.jsx";
import Hero from "../components/Hero.jsx";
import Skeleton from "../components/ui/Skeleton.jsx";
const CATEGORIES = ["All Categories", "T-Shirts", "Hoodies", "Quarter Zip", "Caps", "Shorts", "Joggers", "Drinkware", "Accessories"];
import { Filter, ChevronDown, X, LayoutGrid, Search, Package } from "lucide-react";
import shopHero from "../assets/shop-hero.jpg";

export default function Shop() {
  const location = useLocation();
  const collections = useQuery(api.collections.list);
  const [category, setCategory] = useState("All Categories");
  const [sort, setSort] = useState("Featured");
  const [searchQuery, setSearchQuery] = useState("");

  // Sync search query from URL
  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const q = params.get("q");
    if (q) setSearchQuery(q);
    else setSearchQuery("");
  }, [location.search]);

  const convexProducts = useQuery(api.products.list);
  const PRODUCTS = convexProducts || [];
  const isLoading = convexProducts === undefined;
  
  // Fetch product sets
  const convexProductSets = useQuery(api.products.listProductSets);
  const productSets = convexProductSets || [];
  const isLoadingSets = convexProductSets === undefined;

  const itemsByCollection = useMemo(() => {
    let filtered = PRODUCTS.filter((p) =>
      category === "All Categories" ? true : p.category === category
    );

    // Filter by search query if present
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      filtered = filtered.filter(p =>
        p.name.toLowerCase().includes(q) ||
        (p.description && p.description.toLowerCase().includes(q)) ||
        p.category.toLowerCase().includes(q)
      );
    }

    // Apply sorting
    let sorted = [...filtered];
    if (sort === "Price: Low to High") sorted.sort((a, b) => a.price - b.price);
    if (sort === "Price: High to Low") sorted.sort((a, b) => b.price - a.price);
    if (sort === "Newest Arrivals") sorted.sort((a, b) => b.id - a.id);

    // Group by collection
    const groups = {};

    // Sort collections: Daustian x Uniwear first, then others alphabetically
    const sortedCollections = collections ? [...collections].sort((a, b) => {
      const aIsDaustian = a.name.toLowerCase().includes("daustian") || a.name.toLowerCase().includes("uniwear");
      const bIsDaustian = b.name.toLowerCase().includes("daustian") || b.name.toLowerCase().includes("uniwear");
      if (aIsDaustian && !bIsDaustian) return -1;
      if (!aIsDaustian && bIsDaustian) return 1;
      return a.name.localeCompare(b.name);
    }) : [];

    // If no collections, create default groups
    if (!collections || collections.length === 0) {
      // Group by category instead
      sorted.forEach(p => {
        const cat = p.category || "Other";
        if (!groups[cat]) groups[cat] = [];
        groups[cat].push(p);
      });
      return groups;
    }

    // Group by collection with proper sorting
    sortedCollections.forEach(c => {
      const productsInCollection = sorted.filter(p => p.collection === c.slug);
      if (productsInCollection.length > 0) {
        groups[c.name] = productsInCollection;
      }
    });

    // Also include products without a collection or with a stale collection slug
    const knownSlugs = new Set(sortedCollections.map(c => c.slug));
    const ungrouped = sorted.filter(p => !p.collection || !knownSlugs.has(p.collection));
    if (ungrouped.length > 0) {
      groups["Other Products"] = ungrouped;
    }

    return groups;
  }, [PRODUCTS, category, sort, searchQuery, collections]);

  const totalItems = Object.values(itemsByCollection).reduce((sum, arr) => sum + arr.length, 0);

  return (
    <main className="min-h-screen bg-gray-50/50">
      <Hero
        title="University Merch"
        subtitle="Rep DAUST with Pride"
        image={shopHero}
      />

      <section className="max-w-7xl mx-auto px-4 py-16 sm:py-24">
        {/* Filters Bar */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8 sm:mb-12">
          <div className="flex items-center gap-3">
            <Filter className="text-brand-navy" size={18} />
            <span className="font-black text-brand-navy uppercase tracking-widest text-xs">Filter:</span>
          </div>

          <div className="flex flex-wrap items-center gap-3">
            {/* Category Filter */}
            <div className="relative group">
              <button className="flex items-center gap-2 sm:gap-3 px-4 sm:px-5 py-2.5 sm:py-3 bg-white rounded-full shadow-sm border border-gray-100 hover:border-brand-orange transition-all font-bold text-xs sm:text-sm whitespace-nowrap">
                <span className="hidden sm:inline">{category}</span>
                <span className="sm:hidden">Category</span>
                <ChevronDown size={14} className="text-gray-400 group-hover:text-brand-orange transition-colors" />
              </button>

              <div className="absolute top-full left-0 mt-2 w-48 sm:w-56 bg-white rounded-2xl shadow-xl border border-gray-100 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-50">
                <div className="p-2">
                  {CATEGORIES.map(cat => (
                    <button
                      key={cat}
                      onClick={() => setCategory(cat)}
                      className={`w-full text-left px-3 sm:px-4 py-2.5 sm:py-3 rounded-xl text-xs sm:text-sm font-bold transition-all ${category === cat
                          ? "bg-brand-navy text-white"
                          : "text-gray-600 hover:bg-gray-50 hover:text-brand-orange"
                        }`}
                    >
                      {cat}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* Sort */}
            <div className="relative group">
              <button className="flex items-center gap-2 sm:gap-3 px-4 sm:px-5 py-2.5 sm:py-3 bg-white rounded-full shadow-sm border border-gray-100 hover:border-brand-orange transition-all font-bold text-xs sm:text-sm whitespace-nowrap">
                <span className="hidden sm:inline">{sort}</span>
                <span className="sm:hidden">Sort</span>
                <ChevronDown size={14} className="text-gray-400 group-hover:text-brand-orange transition-colors" />
              </button>

              <div className="absolute top-full right-0 mt-2 w-48 sm:w-56 bg-white rounded-2xl shadow-xl border border-gray-100 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all z-50">
                <div className="p-2">
                  {["Featured", "Price: Low to High", "Price: High to Low", "Newest Arrivals"].map(s => (
                    <button
                      key={s}
                      onClick={() => setSort(s)}
                      className={`w-full text-left px-3 sm:px-4 py-2.5 sm:py-3 rounded-xl text-xs sm:text-sm font-bold transition-all ${sort === s
                          ? "bg-brand-navy text-white"
                          : "text-gray-600 hover:bg-gray-50 hover:text-brand-orange"
                        }`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* Search */}
            <div className="relative flex-1 sm:flex-none sm:w-48 lg:w-64">
              <Search className="absolute left-3 sm:left-4 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
              <input
                type="text"
                placeholder="Search..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-9 sm:pl-11 pr-3 sm:pr-4 py-2.5 sm:py-3 bg-white rounded-full shadow-sm border border-gray-100 focus:border-brand-orange focus:ring-4 focus:ring-brand-orange/5 outline-none transition-all w-full font-bold text-xs sm:text-sm"
              />
              {searchQuery && (
                <button
                  onClick={() => setSearchQuery("")}
                  className="absolute right-3 sm:right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-brand-orange"
                >
                  <X size={14} />
                </button>
              )}
            </div>
          </div>
        </div>

        <div className="space-y-12">
          {/* Product Sets Section */}
          {productSets.length > 0 && (
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-700">
              <div className="flex items-center justify-between mb-8 border-b border-gray-100 pb-4">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-brand-orange/10 rounded-xl flex items-center justify-center">
                    <Package className="text-brand-orange" size={20} />
                  </div>
                  <h3 className="text-2xl font-black text-brand-navy tracking-tight uppercase">
                    Special Bundles
                  </h3>
                </div>
                <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">
                  {productSets.length} Sets
                </span>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {productSets.map((set) => (
                  <ProductSetCard key={set._id} productSet={set} />
                ))}
              </div>
            </div>
          )}

          {isLoading ? (
            <div className="grid grid-cols-2 lg:grid-cols-4 gap-x-3 gap-y-8 sm:gap-x-8 sm:gap-y-12">
              {[...Array(8)].map((_, i) => (
                <div key={i} className="space-y-4">
                  <Skeleton className="h-80 w-full rounded-3xl" />
                  <div className="space-y-2">
                    <Skeleton className="h-4 w-3/4" />
                    <Skeleton className="h-6 w-1/3" />
                    <div className="flex justify-between pt-2">
                      <Skeleton className="h-6 w-1/3" />
                      <Skeleton className="h-6 w-6 rounded-lg" />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : totalItems > 0 ? (
            Object.entries(itemsByCollection).map(([colName, products]) => (
              <div key={colName} className="animate-in fade-in slide-in-from-bottom-4 duration-700">
                <div className="flex items-center justify-between mb-8 border-b border-gray-100 pb-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-brand-navy/5 rounded-xl flex items-center justify-center">
                      <LayoutGrid className="text-brand-navy" size={20} />
                    </div>
                    <h3 className="text-2xl font-black text-brand-navy tracking-tight uppercase">
                      {colName}
                    </h3>
                  </div>
                  <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">
                    {products.length} Products
                  </span>
                </div>

                <div className="grid grid-cols-2 lg:grid-cols-4 gap-x-3 gap-y-8 sm:gap-x-8 sm:gap-y-12">
                  {products.map((p) => (
                    <ProductCard key={p.id} product={p} />
                  ))}
                </div>
              </div>
            ))
          ) : (
            <div className="col-span-full py-32 text-center">
              <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-gray-100 mb-6">
                <Filter className="h-8 w-8 text-gray-400" />
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-2">No products found</h3>
              <p className="text-gray-500 mb-8 max-w-sm mx-auto">Try adjusting your filters or search criteria to find what you're looking for.</p>
              <button
                onClick={() => { setCategory("All Categories"); setSort("Featured"); }}
                className="text-brand-orange font-bold uppercase tracking-widest text-sm hover:underline"
              >
                Clear all filters
              </button>
            </div>
          )}
        </div>
      </section>

      <Newsletter />
    </main>
  );
}

import React, { useState, useEffect } from "react";
import { useMutation } from "convex/react";
import { api } from "../../../convex/_generated/api";
import { X, Upload, Image as ImageIcon } from "lucide-react";
import Button from "../../components/ui/Button";
import { optimizeImage, createPreviewUrl, revokePreviewUrl } from "../../utils/imageOptimizer";
import { useAdmin } from "../../context/AdminContext";

export default function CollectionForm({ collection, onClose, onSave }) {
    const { adminToken } = useAdmin();
    const [formData, setFormData] = useState({
        name: "",
        slug: "",
        description: "",
        image: "",
    });
    const [imageFile, setImageFile] = useState(null);
    const [imagePreview, setImagePreview] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const addCollection = useMutation(api.collections.addCollection);
    const updateCollection = useMutation(api.collections.updateCollection);
    const generateUploadUrl = useMutation(api.collections.generateUploadUrl);

    useEffect(() => {
        if (collection) {
            setFormData({
                name: collection.name || "",
                slug: collection.slug || "",
                description: collection.description || "",
                image: collection.image || "",
            });
            setImagePreview(collection.image || "");
        }
    }, [collection]);

    useEffect(() => {
        return () => {
            if (imagePreview && imagePreview.startsWith("blob:")) {
                revokePreviewUrl(imagePreview);
            }
        };
    }, [imagePreview]);

    const generateSlug = (name) => {
        return name
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, "-")
            .replace(/^-+|-+$/g, "");
    };

    const handleNameChange = (e) => {
        const name = e.target.value;
        setFormData({
            ...formData,
            name,
            slug: generateSlug(name),
        });
    };

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            if (imagePreview && imagePreview.startsWith("blob:")) {
                revokePreviewUrl(imagePreview);
            }
            setImageFile(file);
            setImagePreview(createPreviewUrl(file));
        }
    };

    const handleUpload = async (fileToUpload) => {
        if (!fileToUpload) return formData.image;

        const postUrl = await generateUploadUrl();
        const result = await fetch(postUrl, {
            method: "POST",
            headers: { "Content-Type": fileToUpload.type },
            body: fileToUpload,
        });
        const { storageId } = await result.json();
        return storageId;
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        try {
            if (!formData.name.trim()) {
                setError("Collection name is required");
                setLoading(false);
                return;
            }

            let finalImageUrl = formData.image;
            if (imageFile) {
                const optimizedFile = await optimizeImage(imageFile);
                const storageId = await handleUpload(optimizedFile);
                finalImageUrl = storageId;
            }

            const payload = {
                ...formData,
                image: finalImageUrl,
            };

            if (collection) {
                await updateCollection({
                    id: collection._id,
                    ...payload,
                    adminToken,
                });
            } else {
                await addCollection({ ...payload, adminToken });
            }

            onSave();
        } catch (err) {
            setError("An error occurred while saving the collection. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-4xl mx-auto">
            <div>
                {/* Header */}
                <div className="flex items-center justify-between mb-8">
                    <div>
                        <h1 className="text-3xl font-bold text-brand-navy mb-2">
                            {collection ? "Edit Collection" : "Add Collection"}
                        </h1>
                        <p className="text-gray-600">
                            {collection ? "Update collection details" : "Create a new product collection"}
                        </p>
                    </div>
                    <button
                        onClick={onClose}
                        className="p-2 hover:bg-gray-100 rounded-lg transition-colors"
                    >
                        <X size={24} className="text-gray-600" />
                    </button>
                </div>

                {/* Form */}
                <form onSubmit={handleSubmit} className="bg-white rounded-2xl border border-gray-200 p-8">
                    {error && (
                        <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-xl text-red-600">
                            {error}
                        </div>
                    )}

                    <div className="space-y-6">
                        {/* Name */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Collection Name *
                            </label>
                            <input
                                type="text"
                                value={formData.name}
                                onChange={handleNameChange}
                                placeholder="e.g., Life At Daust"
                                className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-brand-orange/20 focus:border-brand-orange transition-all"
                                required
                            />
                        </div>

                        {/* Slug (auto-generated) */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Slug (auto-generated)
                            </label>
                            <input
                                type="text"
                                value={formData.slug}
                                onChange={(e) => setFormData({ ...formData, slug: e.target.value })}
                                placeholder="life-at-daust"
                                className="w-full px-4 py-3 border border-gray-200 rounded-xl bg-gray-50 focus:outline-none focus:ring-2 focus:ring-brand-orange/20 focus:border-brand-orange transition-all"
                            />
                            <p className="text-sm text-gray-500 mt-1">
                                URL-friendly identifier for this collection
                            </p>
                        </div>

                        {/* Description */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Description
                            </label>
                            <textarea
                                value={formData.description}
                                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                placeholder="Brief description of this collection..."
                                rows={4}
                                className="w-full px-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-brand-orange/20 focus:border-brand-orange transition-all resize-none"
                            />
                        </div>

                        {/* Image Upload */}
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-2">
                                Collection Image
                            </label>
                            <div className="mt-1 flex justify-center px-6 pt-5 pb-6 border-2 border-gray-100 border-dashed rounded-2xl bg-gray-50/50 hover:bg-gray-50 transition-colors">
                                <div className="space-y-1 text-center">
                                    {imagePreview ? (
                                        <div className="relative inline-block">
                                            <img
                                                src={imagePreview}
                                                alt="Preview"
                                                className="h-32 w-auto object-cover rounded-xl shadow-md"
                                            />
                                            <button
                                                type="button"
                                                onClick={() => {
                                                    setImageFile(null);
                                                    setImagePreview("");
                                                    setFormData({ ...formData, image: "" });
                                                }}
                                                className="absolute -top-2 -right-2 p-1 bg-white rounded-full border border-gray-200 shadow-sm hover:text-red-500 transition-colors"
                                            >
                                                <X size={14} />
                                            </button>
                                        </div>
                                    ) : (
                                        <>
                                            <div className="mx-auto h-12 w-12 text-gray-400 bg-white rounded-xl flex items-center justify-center shadow-sm">
                                                <ImageIcon size={24} />
                                            </div>
                                            <div className="flex text-sm text-gray-600">
                                                <label className="relative cursor-pointer bg-white rounded-md font-bold text-brand-orange hover:text-brand-orange/80 focus-within:outline-none transition-colors">
                                                    <span>Upload a file</span>
                                                    <input
                                                        type="file"
                                                        className="sr-only"
                                                        onChange={handleImageChange}
                                                        accept="image/*"
                                                    />
                                                </label>
                                                <p className="pl-1">or drag and drop</p>
                                            </div>
                                            <p className="text-xs text-gray-400 uppercase tracking-widest font-bold">
                                                PNG, JPG, GIF up to 10MB
                                            </p>
                                        </>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Actions */}
                    <div className="flex items-center justify-end gap-3 mt-8 pt-6 border-t border-gray-200">
                        <Button
                            type="button"
                            variant="secondary"
                            onClick={onClose}
                            disabled={loading}
                        >
                            Cancel
                        </Button>
                        <Button type="submit" disabled={loading}>
                            {loading ? "Saving..." : collection ? "Update Collection" : "Create Collection"}
                        </Button>
                    </div>
                </form>
            </div>
        </div>
    );
}

import React, { useState } from "react";
import { useQuery, useMutation } from "convex/react";
import { api } from "../../../convex/_generated/api";
import {
    Plus,
    Search,
    Edit2,
    Trash2,
    Package,
} from "lucide-react";
import Button from "../../components/ui/Button";
import LoadingSpinner from "../../components/ui/LoadingSpinner";
import CollectionForm from "./CollectionForm";
import { useAdmin } from "../../context/AdminContext";

export default function AdminCollections() {
    const { adminToken } = useAdmin();
    const [searchQuery, setSearchQuery] = useState("");
    const [showForm, setShowForm] = useState(false);
    const [editingCollection, setEditingCollection] = useState(null);

    const collections = useQuery(api.collections.list);
    const removeCollection = useMutation(api.collections.removeCollection);

    const handleEdit = (collection) => {
        setEditingCollection(collection);
        setShowForm(true);
    };

    const handleDelete = async (id) => {
        if (window.confirm("Are you sure you want to delete this collection? Products will be unassigned from this collection.")) {
            try {
                await removeCollection({ id, adminToken });
            } catch (error) {
                alert("Failed to delete collection. Please try again.");
            }
        }
    };

    const handleFormClose = () => {
        setShowForm(false);
        setEditingCollection(null);
    };

    const filteredCollections = collections?.filter((c) =>
        c.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

    if (collections === undefined) {
        return (
            <div className="flex items-center justify-center min-h-[400px]">
                <LoadingSpinner />
            </div>
        );
    }

    if (showForm) {
        return (
            <CollectionForm
                collection={editingCollection}
                onClose={handleFormClose}
                onSave={handleFormClose}
            />
        );
    }

    return (
        <div className="p-8">
            <div className="max-w-7xl mx-auto">
                {/* Header */}
                <div className="flex items-center justify-between mb-8">
                    <div>
                        <h1 className="text-3xl font-bold text-brand-navy mb-2">Collections</h1>
                        <p className="text-gray-600">Manage product collections and groupings</p>
                    </div>
                    <Button onClick={() => setShowForm(true)} className="gap-2">
                        <Plus size={20} />
                        Add Collection
                    </Button>
                </div>

                {/* Search */}
                <div className="mb-6">
                    <div className="relative max-w-md">
                        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
                        <input
                            type="text"
                            placeholder="Search collections..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full pl-12 pr-4 py-3 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-brand-orange/20 focus:border-brand-orange transition-all"
                        />
                    </div>
                </div>

                {/* Collections Grid */}
                {filteredCollections && filteredCollections.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {filteredCollections.map((collection) => (
                            <div
                                key={collection._id}
                                className="bg-white rounded-2xl border border-gray-200 p-6 hover:shadow-lg transition-all duration-300"
                            >
                                <div className="flex items-center gap-4">
                                    <div className="w-16 h-16 bg-brand-orange/10 rounded-2xl flex items-center justify-center overflow-hidden border border-gray-100 shadow-sm">
                                        {collection.image ? (
                                            <img
                                                src={collection.image}
                                                alt={collection.name}
                                                className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500"
                                            />
                                        ) : (
                                            <Package className="text-brand-orange" size={28} />
                                        )}
                                    </div>
                                    <div>
                                        <h3 className="font-extrabold text-brand-navy text-xl leading-tight">
                                            {collection.name}
                                        </h3>
                                        <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mt-1">/{collection.slug}</p>
                                    </div>
                                </div>

                                {collection.description && (
                                    <p className="text-gray-600 text-sm mb-4 line-clamp-2">
                                        {collection.description}
                                    </p>
                                )}

                                <div className="flex items-center justify-end gap-2 pt-4 border-t border-gray-100">
                                    <button
                                        onClick={() => handleEdit(collection)}
                                        className="p-2 text-gray-400 hover:text-brand-navy hover:bg-gray-100 rounded-lg transition-all"
                                        title="Edit Collection"
                                    >
                                        <Edit2 size={18} />
                                    </button>
                                    <button
                                        onClick={() => handleDelete(collection._id)}
                                        className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                                        title="Delete Collection"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div className="text-center py-16">
                        <div className="w-20 h-20 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                            <Package className="text-gray-400" size={32} />
                        </div>
                        <h3 className="text-xl font-semibold text-gray-900 mb-2">
                            {searchQuery ? "No collections found" : "No collections yet"}
                        </h3>
                        <p className="text-gray-600 mb-6">
                            {searchQuery
                                ? "Try adjusting your search query"
                                : "Get started by creating your first collection"}
                        </p>
                        {!searchQuery && (
                            <Button onClick={() => setShowForm(true)} className="gap-2">
                                <Plus size={20} />
                                Add Collection
                            </Button>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
}

import React, { useMemo } from "react";
import { Link } from "react-router-dom";
import { useQuery } from "convex/react";
import { api } from "../../../convex/_generated/api";
import {
    TrendingUp,
    ShoppingBag,
    Package,
    Clock,
    CheckCircle2,
    DollarSign,
    Users,
    Layers
} from "lucide-react";
import { formatPrice } from "../../utils/format.js";
import LoadingSpinner from "../../components/ui/LoadingSpinner";
import { useAdmin } from "../../context/AdminContext";

export default function AdminDashboard() {
    const { adminToken } = useAdmin();
    const products = useQuery(api.products.list);
    const orders = useQuery(api.orders.list, adminToken ? { adminToken } : "skip");

    const isLoading = products === undefined || (adminToken ? orders === undefined : false);
    // If no admin token (or orders query was skipped), treat as empty 
    const ordersData = orders ?? [];

    const stats = useMemo(() => {
        if (!products) return [];

        const totalRevenue = ordersData.reduce((sum, order) => sum + (order?.total || 0), 0);
        const activeOrders = ordersData.filter(o => o.status === "Processing" || o.status === "Shipped").length;
        const totalProducts = products.length;
        const completedOrders = ordersData.filter(o => o.status === "Delivered").length;

        return [
            { label: "Total Revenue", value: formatPrice(totalRevenue), icon: DollarSign, color: "bg-green-50 text-green-600" },
            { label: "Active Orders", value: activeOrders.toString(), icon: ShoppingBag, color: "bg-brand-orange/10 text-brand-orange" },
            { label: "Catalog Size", value: totalProducts.toString(), icon: Package, color: "bg-blue-50 text-blue-600" },
            { label: "Fulfillment Rate", value: ordersData.length > 0 ? `${Math.round((completedOrders / ordersData.length) * 100)}%` : "0%", icon: CheckCircle2, color: "bg-purple-50 text-purple-600" },
        ];
    }, [products, ordersData]);

    const recentOrders = useMemo(() => {
        return ordersData.slice(0, 5);
    }, [ordersData]);

    const topCategories = useMemo(() => {
        if (!products) return [];
        const counts = {};
        products.forEach(p => {
            const cat = p.category || "Uncategorized";
            counts[cat] = (counts[cat] || 0) + 1;
        });
        return Object.entries(counts).sort((a, b) => b[1] - a[1]).slice(0, 4);
    }, [products]);

    if (isLoading) {
        return (
            <div className="h-full flex flex-col items-center justify-center space-y-4">
                <LoadingSpinner size="lg" />
                <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">Analytics Loading...</p>
            </div>
        );
    }

    return (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Header Section */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
                <div>
                    <h1 className="text-4xl font-[900] text-brand-navy tracking-tight mb-2">Workspace Overview</h1>
                    <p className="text-gray-400 font-medium italic text-lg">&ldquo;Excellence is not an act, but a habit.&rdquo;</p>
                </div>
                <div className="flex items-center gap-3 bg-brand-navy/5 px-6 py-4 rounded-2xl border border-brand-navy/5">
                    <Clock size={18} className="text-brand-navy/30" />
                    <span className="text-sm font-bold text-brand-navy/60 uppercase tracking-widest">{new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}</span>
                </div>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                {stats.map((stat, i) => (
                    <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-2xl shadow-black/[0.02] hover:shadow-black/[0.05] hover:-translate-y-1 transition-all duration-500 group relative overflow-hidden">
                        <div className="absolute top-0 right-0 w-24 h-24 bg-brand-orange/5 rounded-full blur-2xl -mr-12 -mt-12 group-hover:bg-brand-orange/10 transition-colors" />
                        <div className="flex items-center justify-between mb-8">
                            <div className={`p-4 rounded-2xl ${stat.color} shadow-sm group-hover:scale-110 transition-transform duration-500`}>
                                <stat.icon size={26} />
                            </div>
                        </div>
                        <p className="text-[11px] font-black uppercase tracking-[0.2em] text-gray-400 mb-2">{stat.label}</p>
                        <p className="text-3xl font-[900] text-brand-navy tracking-tighter">{stat.value}</p>
                    </div>
                ))}
            </div>

            <div className="grid lg:grid-cols-12 gap-10">
                {/* Recent Activity */}
                <div className="lg:col-span-8 bg-white p-10 rounded-[3rem] border border-gray-100 shadow-2xl shadow-black/[0.02] relative overflow-hidden">
                    <div className="flex justify-between items-center mb-10">
                        <div className="flex items-center gap-4">
                            <div className="w-1.5 h-8 bg-brand-orange rounded-full" />
                            <h2 className="text-2xl font-[900] text-brand-navy tracking-tight">Recent Activity</h2>
                        </div>
                        <button className="px-6 py-2.5 bg-gray-50 hover:bg-brand-orange hover:text-white text-brand-navy text-[10px] font-black uppercase tracking-widest rounded-full transition-all duration-300">View Analytics</button>
                    </div>

                    <div className="space-y-6">
                        {recentOrders.map((order) => (
                            <div key={order._id} className="flex items-center justify-between p-7 bg-gray-50/50 rounded-[2rem] border border-transparent hover:border-brand-orange/10 hover:bg-white hover:shadow-xl hover:shadow-black/5 transition-all duration-500 group">
                                <div className="flex items-center gap-6">
                                    <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center shadow-lg shadow-black/5 group-hover:bg-brand-navy group-hover:text-white transition-all duration-500">
                                        <ShoppingBag size={24} className="group-hover:scale-110 transition-transform" />
                                    </div>
                                    <div>
                                        <p className="font-[900] text-brand-navy text-lg tracking-tight mb-1">Order {order.orderId}</p>
                                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest flex items-center gap-2">
                                            {order.customer.name}
                                            <span className="w-1 h-1 bg-gray-300 rounded-full" />
                                            {order.items.length} items
                                        </p>
                                    </div>
                                </div>
                                <div className="text-right flex items-center gap-10">
                                    <div className="hidden sm:block">
                                        <p className="font-[900] text-brand-navy text-lg tracking-tighter mb-1">{formatPrice(order.total)}</p>
                                        <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest">{new Date(order.createdAt).toLocaleDateString()}</p>
                                    </div>
                                    <span className={`text-[10px] font-black uppercase tracking-[0.15em] px-5 py-2 rounded-full border ${order.status === "Processing" ? "bg-brand-orange/5 text-brand-orange border-brand-orange/10" :
                                        order.status === "Shipped" ? "bg-blue-50 text-blue-600 border-blue-100" :
                                            "bg-green-50 text-green-600 border-green-100"
                                        }`}>
                                        {order.status}
                                    </span>
                                </div>
                            </div>
                        ))}

                        {recentOrders.length === 0 && (
                            <div className="text-center py-32 bg-gray-50/50 rounded-[2.5rem] border border-dashed border-gray-200">
                                <div className="inline-flex p-6 bg-white rounded-2xl shadow-sm mb-4">
                                    <Package size={32} className="text-gray-300" />
                                </div>
                                <p className="text-gray-400 font-black uppercase tracking-[0.2em] text-xs">No recent orders identified</p>
                            </div>
                        )}
                    </div>
                </div>

                {/* Sidebar Column */}
                <div className="lg:col-span-4 space-y-10">
                    {/* Inventory Share Card */}
                    <div className="bg-brand-navy p-10 rounded-[3rem] text-white shadow-2xl shadow-brand-navy/40 relative overflow-hidden group">
                        <div className="absolute top-0 right-0 w-48 h-48 bg-white/5 rounded-full blur-[80px] -mr-24 -mt-24 group-hover:bg-brand-orange/10 transition-all duration-700" />
                        <h2 className="text-xl font-[900] tracking-tight mb-10 relative z-10 flex items-center gap-3">
                            <Layers size={20} className="text-brand-orange" />
                            Inventory Share
                        </h2>
                        <div className="space-y-8 relative z-10">
                            {topCategories.map(([cat, count], i) => (
                                <div key={i} className="space-y-3 group/item">
                                    <div className="flex justify-between items-center text-xs font-black uppercase tracking-widest">
                                        <span className="text-brand-cream/40 group-hover/item:text-white transition-colors">{cat}</span>
                                        <span className="text-brand-orange">{count} items</span>
                                    </div>
                                    <div className="h-2 bg-white/5 rounded-full overflow-hidden border border-white/5">
                                        <div
                                            className="h-full bg-gradient-to-r from-brand-orange to-orange-400 rounded-full transition-all duration-[1.5s] ease-out shadow-[0_0_12px_rgba(255,107,0,0.3)]"
                                            style={{ width: `${(count / products.length) * 100}%` }}
                                        />
                                    </div>
                                </div>
                            ))}

                            {topCategories.length === 0 && (
                                <p className="text-brand-cream/20 text-xs italic text-center py-14">Awaiting catalog data...</p>
                            )}
                        </div>
                    </div>

                    {/* Quick Access Card */}
                    <div className="bg-white p-10 rounded-[3rem] border border-gray-100 shadow-2xl shadow-black/[0.02]">
                        <h2 className="text-xl font-[900] text-brand-navy tracking-tight mb-8">Quick Access</h2>
                        <div className="grid grid-cols-2 gap-5">
                            <Link to="/admin/products" className="flex flex-col items-center justify-center p-6 bg-gray-50/50 rounded-[2rem] hover:bg-brand-navy hover:text-white transition-all duration-500 gap-3 group">
                                <Package size={24} className="group-hover:scale-110 transition-transform" />
                                <span className="text-[10px] font-black uppercase tracking-widest">Inventory</span>
                            </Link>
                            <Link to="/admin/orders" className="flex flex-col items-center justify-center p-6 bg-gray-50/50 rounded-[2rem] hover:bg-brand-orange hover:text-white transition-all duration-500 gap-3 group shadow-orange-500/10">
                                <Clock size={24} className="group-hover:scale-110 transition-transform" />
                                <span className="text-[10px] font-black uppercase tracking-widest">Pending</span>
                            </Link>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState } from "react";
import { useQuery, useMutation, useAction } from "convex/react";
import { api } from "../../../convex/_generated/api";
import {
    Package,
    Clock,
    CheckCircle2,
    Truck,
    ChevronRight,
    User,
    Mail,
    Calendar,
    DollarSign,
    AlertCircle,
    Trash2
} from "lucide-react";
import LoadingSpinner from "../../components/ui/LoadingSpinner";
import { useAdmin } from "../../context/AdminContext";

export default function AdminOrders() {
    const { adminToken } = useAdmin();
    const orders = useQuery(api.orders.list, adminToken ? { adminToken } : "skip");
    const updateStatus = useMutation(api.orders.updateStatus);
    const checkNabooStatus = useAction(api.naboopay.getTransaction);
    const deleteNabooTransaction = useAction(api.naboopay.deleteTransaction);
    const deleteOrderMutation = useMutation(api.orders.deleteOrder);
    const [selectedOrder, setSelectedOrder] = useState(null);
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);

    const isLoading = orders === undefined;

    const getStatusColor = (status) => {
        switch (status) {
            case "Pending Verification": return "bg-purple-50 text-purple-600";
            case "Pending Payment": return "bg-yellow-50 text-yellow-600";
            case "Paid": return "bg-green-50 text-green-600 font-bold";
            case "Processing": return "bg-brand-orange/10 text-brand-orange";
            case "Shipped": return "bg-blue-50 text-blue-600";
            case "Delivered": return "bg-green-50 text-green-600";
            case "Cancelled": return "bg-red-50 text-red-600";
            default: return "bg-gray-100 text-gray-600";
        }
    };

    const handleCheckStatus = async (naboopayId) => {
        try {
            const result = await checkNabooStatus({ orderId: naboopayId });
            if (result && result.transaction_status) {
                alert(`NabooPay Status: ${result.transaction_status}`);
            }
        } catch (err) {
            alert("Failed to check status. Make sure the NabooPay ID is valid.");
        }
    };

    const handleStatusUpdate = async (id, newStatus) => {
        try {
            if (newStatus === "Cancelled" && selectedOrder.naboopayOrderId) {
                try {
                    await deleteNabooTransaction({ orderId: selectedOrder.naboopayOrderId });
                } catch (err) {
                    // Continue anyway ΓÇö transaction may already be deleted or expired
                }
            }
            await updateStatus({ id, status: newStatus, adminToken });
            if (selectedOrder && selectedOrder._id === id) {
                setSelectedOrder({ ...selectedOrder, status: newStatus });
            }
        } catch (err) {
            alert("Failed to update order status. Please try again.");
        }
    };

    const handleDeleteOrder = async () => {
        try {
            await deleteOrderMutation({ id: selectedOrder._id, adminToken });
            setSelectedOrder(null);
            setShowDeleteConfirm(false);
        } catch (err) {
            alert("Failed to delete order. Please try again.");
        }
    };

    if (isLoading) {
        return (
            <div className="h-full flex flex-col items-center justify-center space-y-4">
                <LoadingSpinner size="lg" />
                <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">Loading Orders...</p>
            </div>
        );
    }

    return (
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            {/* Orders List */}
            <div className={`${selectedOrder ? "lg:col-span-4" : "lg:col-span-12"} transition-all duration-500`}>
                <div className="bg-white rounded-[2rem] border border-gray-100 shadow-sm overflow-hidden">
                    <div className="p-6 border-b border-gray-50">
                        <h2 className="text-lg font-black text-brand-navy">All Orders</h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">{orders.length} total shipments</p>
                    </div>

                    <div className="divide-y divide-gray-50 max-h-[calc(100vh-250px)] overflow-y-auto pr-1">
                        {orders.map((order) => (
                            <button
                                key={order._id}
                                onClick={() => setSelectedOrder(order)}
                                className={`w-full text-left p-6 hover:bg-gray-50 transition-all flex items-center justify-between group ${selectedOrder?._id === order._id ? "bg-gray-50 ring-1 ring-inset ring-brand-orange/10" : ""
                                    }`}
                            >
                                <div>
                                    <div className="flex items-center gap-2 mb-1">
                                        <span className="font-black text-brand-navy text-sm">{order.orderId}</span>
                                        <span className={`text-[9px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full ${getStatusColor(order.status)}`}>
                                            {order.status}
                                        </span>
                                    </div>
                                    <p className="text-xs font-bold text-gray-500">{order.customer.name}</p>
                                    <p className="text-[10px] text-gray-400 mt-1">{new Date(order.createdAt).toLocaleDateString()}</p>
                                </div>
                                <div className="text-right flex items-center gap-3">
                                    <p className="font-black text-brand-navy text-sm">${(order?.total || 0).toFixed(2)}</p>
                                    <ChevronRight size={16} className={`text-gray-300 group-hover:text-brand-orange transition-all ${selectedOrder?._id === order._id ? "translate-x-1 text-brand-orange" : ""}`} />
                                </div>
                            </button>
                        ))}

                        {orders.length === 0 && (
                            <div className="p-20 text-center">
                                <div className="w-16 h-16 rounded-full bg-gray-50 flex items-center justify-center mx-auto mb-4">
                                    <Package className="h-8 w-8 text-gray-200" />
                                </div>
                                <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">No orders placed yet</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            {/* Order Details */}
            {selectedOrder && (
                <div className="lg:col-span-8 animate-in slide-in-from-right-4 duration-500">
                    <div className="bg-white rounded-[2rem] border border-gray-100 shadow-xl overflow-hidden sticky top-8">
                        <div className="p-8 border-b border-gray-50 flex justify-between items-center bg-gray-50/30">
                            <div>
                                <div className="flex items-center gap-3 mb-1">
                                    <h2 className="text-xl font-black text-brand-navy">{selectedOrder.orderId}</h2>
                                    <span className={`text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full ${getStatusColor(selectedOrder.status)}`}>
                                        {selectedOrder.status}
                                    </span>
                                </div>
                                <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">
                                    Placed on {new Date(selectedOrder.createdAt).toLocaleString()}
                                </p>
                            </div>
                            <div className="flex items-center gap-3">
                                <button
                                    onClick={() => setShowDeleteConfirm(true)}
                                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-xl bg-red-50 text-red-600 hover:bg-red-600 hover:text-white font-bold text-xs uppercase tracking-widest transition-all"
                                >
                                    <Trash2 size={14} /> Delete
                                </button>
                                <button
                                    onClick={() => setSelectedOrder(null)}
                                    className="text-gray-400 hover:text-brand-navy font-bold text-xs uppercase tracking-widest"
                                >
                                    Close Details
                                </button>
                            </div>
                        </div>

                        <div className="p-8 space-y-10">
                            {/* Status Actions */}
                            <div className="flex flex-wrap gap-3">
                                <button
                                    onClick={() => handleStatusUpdate(selectedOrder._id, "Processing")}
                                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${selectedOrder.status === "Processing" ? "bg-brand-orange text-white shadow-lg shadow-brand-orange/20" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                                        }`}
                                >
                                    <Clock size={16} /> Processing
                                </button>
                                <button
                                    onClick={() => handleStatusUpdate(selectedOrder._id, "Shipped")}
                                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${selectedOrder.status === "Shipped" ? "bg-blue-600 text-white shadow-lg shadow-blue-600/20" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                                        }`}
                                >
                                    <Truck size={16} /> Shipped
                                </button>
                                <button
                                    onClick={() => handleStatusUpdate(selectedOrder._id, "Delivered")}
                                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${selectedOrder.status === "Delivered" ? "bg-green-600 text-white shadow-lg shadow-green-600/20" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                                        }`}
                                >
                                    <CheckCircle2 size={16} /> Delivered
                                </button>
                                <button
                                    onClick={() => handleStatusUpdate(selectedOrder._id, "Paid")}
                                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${selectedOrder.status === "Paid" ? "bg-emerald-600 text-white shadow-lg shadow-emerald-600/20" : "bg-emerald-50 text-emerald-600 hover:bg-emerald-100"
                                        }`}
                                >
                                    <CheckCircle2 size={16} /> Paid
                                </button>
                                <button
                                    onClick={() => handleStatusUpdate(selectedOrder._id, "Cancelled")}
                                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${selectedOrder.status === "Cancelled" ? "bg-red-600 text-white shadow-lg shadow-red-600/20" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                                        }`}
                                >
                                    <AlertCircle size={16} /> Cancelled
                                </button>
                                <button
                                    onClick={() => handleStatusUpdate(selectedOrder._id, "Pending Verification")}
                                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${selectedOrder.status === "Pending Verification" ? "bg-purple-600 text-white shadow-lg shadow-purple-600/20" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                                        }`}
                                >
                                    <AlertCircle size={16} /> Pending Verification
                                </button>
                                <button
                                    onClick={() => handleStatusUpdate(selectedOrder._id, "Pending Payment")}
                                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-bold transition-all ${selectedOrder.status === "Pending Payment" ? "bg-yellow-500 text-white shadow-lg shadow-yellow-500/20" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                                        }`}
                                >
                                    <Clock size={16} /> Pending Payment
                                </button>
                            </div>

                            {selectedOrder.naboopayOrderId && (
                                <div className="p-6 bg-blue-50/50 rounded-2xl border border-blue-100 space-y-4">
                                    <div className="flex items-center justify-between">
                                        <h3 className="text-xs font-black uppercase tracking-[0.2em] text-blue-600">NabooPay Transaction</h3>
                                        <button
                                            onClick={() => handleCheckStatus(selectedOrder.naboopayOrderId)}
                                            className="px-3 py-1 bg-white border border-blue-200 rounded-lg text-[10px] font-black text-blue-600 hover:bg-blue-600 hover:text-white transition-all shadow-sm"
                                        >
                                            REFRESH STATUS
                                        </button>
                                    </div>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div>
                                            <p className="text-[10px] font-black uppercase text-blue-400">Order ID</p>
                                            <p className="font-bold text-blue-900 break-all">{selectedOrder.naboopayOrderId}</p>
                                        </div>
                                        <div>
                                            <p className="text-[10px] font-black uppercase text-blue-400">Checkout Link</p>
                                            <a href={selectedOrder.naboopayCheckoutUrl} target="_blank" rel="noreferrer" className="text-xs font-bold text-blue-600 underline">Open Link</a>
                                        </div>
                                    </div>
                                </div>
                            )}

                            {selectedOrder.proofOfPaymentUrl && (
                                <div className="space-y-4">
                                    <h3 className="text-xs font-black uppercase tracking-[0.2em] text-gray-400">Proof of Payment</h3>
                                    <div className="w-full max-w-sm rounded-2xl overflow-hidden border border-gray-100 shadow-sm bg-gray-50">
                                        <a href={selectedOrder.proofOfPaymentUrl} target="_blank" rel="noreferrer">
                                            <img src={selectedOrder.proofOfPaymentUrl} alt="Proof of payment" className="w-full object-cover hover:opacity-90 transition-opacity" />
                                        </a>
                                    </div>
                                    <p className="text-[10px] text-gray-400 italic font-bold">Click image to view in full size</p>
                                </div>
                            )}

                            <div className="grid md:grid-cols-2 gap-10">
                                {/* Customer Info */}
                                <div className="space-y-6">
                                    <h3 className="text-xs font-black uppercase tracking-[0.2em] text-gray-400">Customer Details</h3>
                                    <div className="space-y-4">
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 rounded-xl bg-gray-50 flex items-center justify-center text-gray-400">
                                                <User size={18} />
                                            </div>
                                            <div>
                                                <p className="text-[10px] font-black uppercase text-gray-400">FullName</p>
                                                <p className="font-bold text-brand-navy">{selectedOrder.customer.name}</p>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 rounded-xl bg-gray-50 flex items-center justify-center text-gray-400">
                                                <Mail size={18} />
                                            </div>
                                            <div>
                                                <p className="text-[10px] font-black uppercase text-gray-400">Email Address</p>
                                                <p className="font-bold text-brand-navy">{selectedOrder.customer.email}</p>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-4">
                                            <div className="w-10 h-10 rounded-xl bg-gray-50 flex items-center justify-center text-gray-400">
                                                <Calendar size={18} />
                                            </div>
                                            <div>
                                                <p className="text-[10px] font-black uppercase text-gray-400">Academic Year</p>
                                                <p className="font-bold text-brand-navy">{selectedOrder.customer.year}</p>
                                            </div>
                                        </div>
                                    </div>
                                </div>

                                {/* Items Summary */}
                                <div className="space-y-6">
                                    <h3 className="text-xs font-black uppercase tracking-[0.2em] text-gray-400">Order Items</h3>
                                    <div className="bg-gray-50 rounded-2xl overflow-hidden">
                                        <div className="divide-y divide-gray-100">
                                            {selectedOrder.items.map((item, i) => (
                                                <div key={i} className="p-4 flex items-center justify-between gap-4">
                                                    <div className="flex-1 min-w-0">
                                                        <p className="text-sm font-bold text-brand-navy truncate">{item.name}</p>
                                                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                                                            QTY: {item.qty} {item?.size ? `ΓÇó Size: ${item.size}` : ""} {item?.color ? `ΓÇó ${item.color}` : ""}
                                                        </p>
                                                    </div>
                                                    <p className="font-black text-brand-navy text-sm">${((item.price || 0) * (item.qty || 1)).toFixed(2)}</p>
                                                </div>
                                            ))}
                                        </div>
                                        <div className="p-4 bg-brand-navy text-white flex justify-between items-center">
                                            <span className="text-[10px] font-black uppercase tracking-widest opacity-60">Grand Total</span>
                                            <span className="text-lg font-black">${(selectedOrder?.total || 0).toFixed(2)}</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
            {/* Delete Confirmation Modal */}
            {showDeleteConfirm && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm animate-in fade-in duration-200">
                    <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-sm w-full mx-4 animate-in zoom-in-95 duration-200">
                        <div className="w-12 h-12 rounded-full bg-red-50 flex items-center justify-center mx-auto mb-4">
                            <Trash2 className="h-6 w-6 text-red-600" />
                        </div>
                        <h3 className="text-lg font-black text-brand-navy text-center mb-2">Delete Order?</h3>
                        <p className="text-sm text-gray-500 text-center mb-6">
                            Are you sure you want to delete order <span className="font-bold text-brand-navy">{selectedOrder?.orderId}</span>? This cannot be undone.
                        </p>
                        <div className="flex gap-3">
                            <button
                                onClick={() => setShowDeleteConfirm(false)}
                                className="flex-1 px-4 py-2.5 rounded-xl bg-gray-100 text-gray-600 font-bold text-sm hover:bg-gray-200 transition-all"
                            >
                                Cancel
                            </button>
                            <button
                                onClick={handleDeleteOrder}
                                className="flex-1 px-4 py-2.5 rounded-xl bg-red-600 text-white font-bold text-sm hover:bg-red-700 transition-all shadow-lg shadow-red-600/20"
                            >
                                Delete
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from "react";
import { useMutation, useQuery } from "convex/react";
import { api } from "../../../convex/_generated/api";
import { X, Save, Trash2, Image as ImageIcon, AlertCircle, Plus } from "lucide-react";
import Button from "../../components/ui/Button";
import { optimizeImage, createPreviewUrl, revokePreviewUrl } from "../../utils/imageOptimizer";
import { useAdmin } from "../../context/AdminContext";

export default function AdminProductForm({ product, onSave, onCancel }) {
    const { adminToken } = useAdmin();
    const [formData, setFormData] = useState({
        name: "",
        category: "Accessories",
        price: "",
        rating: 4.5,
        description: "",
        badge: "",
        image: "",
        colors: [],
        sizes: [],
        logos: [],
        logoImages: null,
        collection: "",
        stock: "",
        type: "",
    });

    const [imageFile, setImageFile] = useState(null);
    const [imagePreview, setImagePreview] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const [newColorName, setNewColorName] = useState("");
    const [newColorHex, setNewColorHex] = useState("#000000");
    const [newLogoName, setNewLogoName] = useState("");
    const [newLogoFile, setNewLogoFile] = useState(null);
    const [newLogoPreview, setNewLogoPreview] = useState("");
    const [logoUploading, setLogoUploading] = useState(false);

    const generateUploadUrl = useMutation(api.products.generateUploadUrl);
    const addProduct = useMutation(api.products.addProduct);
    const updateProduct = useMutation(api.products.updateProduct);
    const collections = useQuery(api.collections.list);

    const categories = ["T-Shirts", "Hoodies", "Quarter Zip", "Caps", "Shorts", "Joggers", "Drinkware", "Accessories"];

    useEffect(() => {
        if (product) {
            setFormData({
                name: product.name || "",
                category: product.category || "Accessories",
                price: product.price?.toString() || "",
                rating: product.rating || 4.5,
                description: product.description || "",
                badge: product.badge || "",
                image: product.image || "",
                colors: product.colors || [],
                sizes: product.sizes || [],
                logos: product.logos || [],
                logoImages: product.logoImages || null,
                collection: product.collection || "",
                stock: product.stock?.toString() || "",
                type: product.type || "",
            });
            setImagePreview(product.image || "");
        }
    }, [product]);

    useEffect(() => {
        return () => {
            if (imagePreview && imagePreview.startsWith("blob:")) {
                revokePreviewUrl(imagePreview);
            }
        };
    }, [imagePreview]);

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            if (imagePreview && imagePreview.startsWith("blob:")) {
                revokePreviewUrl(imagePreview);
            }
            setImageFile(file);
            setImagePreview(createPreviewUrl(file));
        }
    };

    const handleUpload = async (fileToUpload) => {
        if (!fileToUpload) return formData.image;
        const postUrl = await generateUploadUrl();
        const result = await fetch(postUrl, {
            method: "POST",
            headers: { "Content-Type": fileToUpload.type },
            body: fileToUpload,
        });
        const { storageId } = await result.json();
        return storageId;
    };

    const addColor = () => {
        if (newColorName.trim()) {
            setFormData({
                ...formData,
                colors: [...formData.colors, { name: newColorName.trim(), hex: newColorHex }]
            });
            setNewColorName("");
            setNewColorHex("#000000");
        }
    };

    const removeColor = (index) => {
        setFormData({
            ...formData,
            colors: formData.colors.filter((_, i) => i !== index)
        });
    };

    const addLogo = async () => {
        if (!newLogoName.trim()) return;
        setLogoUploading(true);
        try {
            let imageStorageId = undefined;
            if (newLogoFile) {
                const optimizedFile = await optimizeImage(newLogoFile);
                const postUrl = await generateUploadUrl();
                const result = await fetch(postUrl, {
                    method: "POST",
                    headers: { "Content-Type": optimizedFile.type },
                    body: optimizedFile,
                });
                const { storageId } = await result.json();
                imageStorageId = storageId;
            }
            const logoId = `logo-${Date.now()}-${Math.random().toString(36).substring(2, 6)}`;
            setFormData({
                ...formData,
                logos: [...formData.logos, { id: logoId, name: newLogoName.trim(), ...(imageStorageId ? { image: imageStorageId } : {}) }]
            });
            setNewLogoName("");
            setNewLogoFile(null);
            if (newLogoPreview) {
                revokePreviewUrl(newLogoPreview);
                setNewLogoPreview("");
            }
        } catch {
            setError("Failed to upload logo image. Please try again.");
        } finally {
            setLogoUploading(false);
        }
    };

    const removeLogo = (index) => {
        setFormData({
            ...formData,
            logos: formData.logos.filter((_, i) => i !== index)
        });
    };

    const addSize = (size) => {
        if (size.trim() && !formData.sizes.includes(size.trim())) {
            setFormData({
                ...formData,
                sizes: [...formData.sizes, size.trim()]
            });
        }
    };

    const removeSize = (index) => {
        setFormData({
            ...formData,
            sizes: formData.sizes.filter((_, i) => i !== index)
        });
    };

    const defaultSizes = ["XS", "S", "M", "L", "XL", "XXL"];

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        try {
            let finalImageUrl = formData.image;
            if (imageFile) {
                const optimizedFile = await optimizeImage(imageFile);
                const storageId = await handleUpload(optimizedFile);
                finalImageUrl = storageId;
            }

            const payload = {
                ...formData,
                price: parseFloat(formData.price),
                rating: parseFloat(formData.rating),
                stock: formData.stock !== "" ? parseInt(formData.stock) : undefined,
                image: finalImageUrl,
                type: formData.category === "Hoodies" ? formData.type : undefined,
            };

            if (product) {
                await updateProduct({ id: product._id, ...payload, adminToken });
            } else {
                await addProduct({ ...payload, adminToken });
            }

            onSave();
        } catch (err) {
            setError("An error occurred while saving the product. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="bg-white rounded-2xl md:rounded-[2rem] border border-gray-100 shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-300 max-h-[90vh] overflow-y-auto">
            <div className="p-4 md:p-8 border-b border-gray-50 flex justify-between items-center sticky top-0 bg-white z-10">
                <div>
                    <h2 className="text-lg md:text-xl font-black text-brand-navy">{product ? "Edit Product" : "Add New Product"}</h2>
                    <p className="text-[10px] md:text-xs text-gray-400 font-bold uppercase tracking-widest">{product ? `Editing ID: ${product._id}` : "Enter product details"}</p>
                </div>
                <button onClick={onCancel} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                    <X size={20} className="text-gray-400" />
                </button>
            </div>

            <form onSubmit={handleSubmit} className="p-4 md:p-8 space-y-6 md:space-y-8">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-12">
                    <div className="space-y-4 md:space-y-6">
                        <div>
                            <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Product Name</label>
                            <input
                                type="text"
                                required
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all"
                                placeholder="DAUST Varsity Jacket"
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-3 md:gap-4">
                            <div>
                                <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Category</label>
                                <select
                                    value={formData.category}
                                    onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                                    className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all appearance-none"
                                >
                                    {categories.map(c => <option key={c} value={c}>{c}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Price (XOF)</label>
                                <input
                                    type="number"
                                    step="100"
                                    required
                                    value={formData.price}
                                    onChange={(e) => setFormData({ ...formData, price: e.target.value })}
                                    className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all"
                                    placeholder="7500"
                                />
                            </div>
                        </div>

                        {formData.category === "Hoodies" && (
                            <div className="animate-in fade-in slide-in-from-top-2 duration-300">
                                <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Hoodie Type</label>
                                <div className="grid grid-cols-2 gap-3 md:gap-4">
                                    <button
                                        type="button"
                                        onClick={() => setFormData({ ...formData, type: "Zipped" })}
                                        className={`px-4 py-3 md:py-4 rounded-xl md:rounded-2xl text-sm md:text-base font-bold transition-all border-2 ${formData.type === "Zipped"
                                            ? "bg-brand-navy text-white border-brand-navy"
                                            : "bg-gray-50 text-brand-navy border-transparent hover:border-gray-200"
                                            }`}
                                    >
                                        Zipped
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => setFormData({ ...formData, type: "No zip" })}
                                        className={`px-4 py-3 md:py-4 rounded-xl md:rounded-2xl text-sm md:text-base font-bold transition-all border-2 ${formData.type === "No zip"
                                            ? "bg-brand-navy text-white border-brand-navy"
                                            : "bg-gray-50 text-brand-navy border-transparent hover:border-gray-200"
                                            }`}
                                    >
                                        No zip
                                    </button>
                                </div>
                            </div>
                        )}

                        <div>
                            <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Description</label>
                            <textarea
                                rows="3"
                                value={formData.description}
                                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all resize-none"
                                placeholder="Tell the story of this product..."
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-3 md:gap-4">
                            <div>
                                <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Rating</label>
                                <input
                                    type="number"
                                    step="0.1"
                                    min="0"
                                    max="5"
                                    value={formData.rating}
                                    onChange={(e) => setFormData({ ...formData, rating: e.target.value })}
                                    className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all"
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Badge</label>
                                <input
                                    type="text"
                                    value={formData.badge}
                                    onChange={(e) => setFormData({ ...formData, badge: e.target.value })}
                                    className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all"
                                    placeholder="New, Popular, etc."
                                />
                            </div>
                        </div>
                    </div>

                    <div className="space-y-4 md:space-y-6">
                        <div>
                            <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Product Image</label>
                            <div
                                className={`relative aspect-[3/4] rounded-2xl md:rounded-3xl overflow-hidden border-2 border-dashed transition-all flex flex-col items-center justify-center p-3 md:p-4 bg-gray-50 ${imagePreview ? "border-transparent" : "border-gray-200 hover:border-brand-orange/40"}`}
                            >
                                {imagePreview ? (
                                    <>
                                        <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
                                        <button
                                            type="button"
                                            onClick={() => { setImageFile(null); setImagePreview(""); setFormData({ ...formData, image: "" }) }}
                                            className="absolute top-2 md:top-4 right-2 md:right-4 bg-red-500 text-white p-1.5 md:p-2 rounded-lg md:rounded-xl shadow-lg hover:bg-red-600 transition-colors"
                                        >
                                            <Trash2 size={16} md:size={20} />
                                        </button>
                                    </>
                                ) : (
                                    <div className="text-center">
                                        <div className="inline-flex items-center justify-center w-12 h-12 md:w-16 md:h-16 rounded-full bg-white mb-3 md:mb-4 shadow-sm text-gray-400">
                                            <ImageIcon size={24} md:size={32} />
                                        </div>
                                        <p className="text-xs md:text-sm font-bold text-gray-500 mb-1">Click to upload image</p>
                                        <p className="text-[8px] md:text-[10px] text-gray-400 font-bold uppercase tracking-widest">Recommended: 1200 x 1600px</p>
                                    </div>
                                )}
                                <input
                                    type="file"
                                    accept="image/*"
                                    onChange={handleImageChange}
                                    className="absolute inset-0 opacity-0 cursor-pointer"
                                />
                            </div>
                        </div>
                    </div>
                </div>

                <div className="bg-gray-50 rounded-2xl md:rounded-3xl p-4 md:p-8">
                    <h3 className="font-black text-brand-navy mb-3 md:mb-4 text-sm md:text-base">Colors</h3>
                    <div className="flex flex-wrap gap-2 md:gap-3 mb-3 md:mb-4">
                        {formData.colors.map((color, index) => (
                            <div key={index} className="flex items-center gap-2 bg-white px-2 md:px-3 py-1.5 md:py-2 rounded-lg md:rounded-xl shadow-sm">
                                <span className="w-4 h-4 md:w-5 md:h-5 rounded-full border border-gray-200" style={{ backgroundColor: color.hex }} />
                                <span className="text-xs md:text-sm font-bold text-brand-navy">{color.name}</span>
                                <button type="button" onClick={() => removeColor(index)} className="text-gray-400 hover:text-red-500">
                                    <X size={12} md:size={14} />
                                </button>
                            </div>
                        ))}
                    </div>
                    <div className="flex gap-2 md:gap-3 items-end">
                        <div className="flex-1">
                            <input
                                type="text"
                                value={newColorName}
                                onChange={(e) => setNewColorName(e.target.value)}
                                placeholder="Color name"
                                className="w-full bg-white border-none rounded-xl px-3 md:px-4 py-2.5 md:py-3 text-xs md:text-sm font-bold"
                            />
                        </div>
                        <div>
                            <input
                                type="color"
                                value={newColorHex}
                                onChange={(e) => setNewColorHex(e.target.value)}
                                className="w-10 h-10 md:w-12 md:h-12 rounded-lg md:rounded-xl cursor-pointer border-none"
                            />
                        </div>
                        <button
                            type="button"
                            onClick={addColor}
                            className="bg-brand-navy text-white px-3 md:px-4 py-2.5 md:py-3 rounded-lg md:rounded-xl font-bold text-xs md:text-sm hover:bg-brand-navy/90"
                        >
                            <Plus size={18} md:size={20} />
                        </button>
                    </div>
                </div>

                <div className="bg-gray-50 rounded-2xl md:rounded-3xl p-4 md:p-8">
                    <h3 className="font-black text-brand-navy mb-3 md:mb-4 text-sm md:text-base">Logo Types</h3>
                    <div className="flex flex-wrap gap-2 md:gap-3 mb-3 md:mb-4">
                        {formData.logos.map((logo, index) => (
                            <div key={index} className="flex items-center gap-2 bg-white px-2 md:px-3 py-1.5 md:py-2 rounded-lg md:rounded-xl shadow-sm">
                                {logo.image && (
                                    <img src={logo.image.startsWith("kg") ? "" : logo.image} alt={logo.name} className="w-8 h-8 rounded-lg object-cover bg-gray-100" />
                                )}
                                <span className="text-xs md:text-sm font-bold text-brand-navy">{logo.name}</span>
                                <button type="button" onClick={() => removeLogo(index)} className="text-gray-400 hover:text-red-500">
                                    <X size={12} />
                                </button>
                            </div>
                        ))}
                    </div>
                    <div className="flex gap-2 md:gap-3 items-end">
                        <div className="flex-1">
                            <input
                                type="text"
                                value={newLogoName}
                                onChange={(e) => setNewLogoName(e.target.value)}
                                placeholder="Logo display name"
                                className="w-full bg-white border-none rounded-xl px-3 md:px-4 py-2.5 md:py-3 text-xs md:text-sm font-bold"
                            />
                        </div>
                        <div className="relative flex-shrink-0">
                            {newLogoPreview ? (
                                <div className="relative w-11 h-11 md:w-12 md:h-12 rounded-xl overflow-hidden border border-gray-200">
                                    <img src={newLogoPreview} alt="Logo preview" className="w-full h-full object-cover" />
                                    <button type="button" onClick={() => { setNewLogoFile(null); revokePreviewUrl(newLogoPreview); setNewLogoPreview(""); }} className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full p-0.5">
                                        <X size={10} />
                                    </button>
                                </div>
                            ) : (
                                <label className="flex items-center justify-center w-11 h-11 md:w-12 md:h-12 bg-white rounded-xl cursor-pointer hover:bg-gray-100 transition-colors border border-dashed border-gray-300">
                                    <ImageIcon size={18} className="text-gray-400" />
                                    <input type="file" accept="image/*" className="hidden" onChange={(e) => {
                                        const f = e.target.files[0];
                                        if (f) { setNewLogoFile(f); setNewLogoPreview(createPreviewUrl(f)); }
                                    }} />
                                </label>
                            )}
                        </div>
                        <button
                            type="button"
                            onClick={addLogo}
                            disabled={logoUploading || !newLogoName.trim()}
                            className="bg-brand-navy text-white px-3 md:px-4 py-2.5 md:py-3 rounded-lg md:rounded-xl font-bold text-xs md:text-sm hover:bg-brand-navy/90 disabled:opacity-50"
                        >
                            {logoUploading ? "..." : <Plus size={18} />}
                        </button>
                    </div>
                </div>

                <div className="bg-gray-50 rounded-2xl md:rounded-3xl p-4 md:p-8">
                    <h3 className="font-black text-brand-navy mb-3 md:mb-4 text-sm md:text-base">Sizes</h3>
                    <div className="flex flex-wrap gap-2 md:gap-3 mb-3 md:mb-4">
                        {formData.sizes.map((size, index) => (
                            <div key={index} className="flex items-center gap-2 bg-white px-2 md:px-3 py-1.5 md:py-2 rounded-lg md:rounded-xl shadow-sm">
                                <span className="text-xs md:text-sm font-bold text-brand-navy">{size}</span>
                                <button type="button" onClick={() => removeSize(index)} className="text-gray-400 hover:text-red-500">
                                    <X size={12} md:size={14} />
                                </button>
                            </div>
                        ))}
                    </div>
                    <div className="flex flex-wrap gap-2">
                        {defaultSizes.map(size => (
                            <button
                                key={size}
                                type="button"
                                onClick={() => addSize(size)}
                                disabled={formData.sizes.includes(size)}
                                className={`px-3 md:px-4 py-2 md:py-2 rounded-lg md:rounded-xl font-bold text-xs md:text-sm ${formData.sizes.includes(size)
                                    ? "bg-gray-200 text-gray-400 cursor-not-allowed"
                                    : "bg-white text-brand-navy hover:bg-brand-navy hover:text-white"
                                    }`}
                            >
                                + {size}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Variant Images Section - per color only */}
                {formData.colors.length > 0 && (
                    <div className="bg-gray-50 rounded-2xl md:rounded-3xl p-4 md:p-8">
                        <h3 className="font-black text-brand-navy mb-1 text-sm md:text-base">Color Images</h3>
                        <p className="text-[10px] text-gray-400 font-bold mb-4">Upload images for each color. These show when a customer selects that color.</p>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                            {formData.colors.map((color) => {
                                const images = formData.logoImages?.["_default"]?.[color.name] || [];
                                return (
                                    <div key={color.name} className="bg-white rounded-xl p-3 border border-gray-100">
                                        <div className="flex items-center gap-2 mb-2">
                                            <span className="w-4 h-4 rounded-full border border-gray-200" style={{ backgroundColor: color.hex }} />
                                            <span className="text-xs font-bold text-brand-navy">{color.name}</span>
                                            <span className="text-[10px] text-gray-400 ml-auto">{images.length} image{images.length !== 1 ? "s" : ""}</span>
                                        </div>
                                        <div className="flex flex-wrap gap-1.5 mb-2">
                                            {images.map((img, idx) => (
                                                <div key={idx} className="relative w-14 h-14 rounded-lg overflow-hidden bg-gray-100 group">
                                                    <img src={typeof img === "string" && !img.startsWith("kg") ? img : ""} alt="" className="w-full h-full object-cover" />
                                                    <button
                                                        type="button"
                                                        onClick={() => {
                                                            const updated = { ...formData.logoImages };
                                                            updated["_default"][color.name] = updated["_default"][color.name].filter((_, i) => i !== idx);
                                                            setFormData({ ...formData, logoImages: updated });
                                                        }}
                                                        className="absolute inset-0 bg-black/50 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity"
                                                    >
                                                        <X size={14} className="text-white" />
                                                    </button>
                                                </div>
                                            ))}
                                            <label className="w-14 h-14 rounded-lg border-2 border-dashed border-gray-200 flex items-center justify-center cursor-pointer hover:border-brand-orange/40 transition-colors bg-gray-50">
                                                <Plus size={16} className="text-gray-400" />
                                                <input
                                                    type="file"
                                                    accept="image/*"
                                                    multiple
                                                    className="hidden"
                                                    onChange={async (e) => {
                                                        const files = Array.from(e.target.files || []);
                                                        if (files.length === 0) return;
                                                        const updated = { ...(formData.logoImages || {}) };
                                                        if (!updated["_default"]) updated["_default"] = {};
                                                        if (!updated["_default"][color.name]) updated["_default"][color.name] = [];
                                                        for (const file of files) {
                                                            const optimized = await optimizeImage(file);
                                                            const postUrl = await generateUploadUrl();
                                                            const result = await fetch(postUrl, {
                                                                method: "POST",
                                                                headers: { "Content-Type": optimized.type },
                                                                body: optimized,
                                                            });
                                                            const { storageId } = await result.json();
                                                            updated["_default"][color.name] = [...updated["_default"][color.name], storageId];
                                                        }
                                                        setFormData(prev => ({ ...prev, logoImages: { ...updated } }));
                                                        e.target.value = "";
                                                    }}
                                                />
                                            </label>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3 md:gap-4">
                    <div>
                        <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Collection</label>
                        <select
                            value={formData.collection}
                            onChange={(e) => setFormData({ ...formData, collection: e.target.value })}
                            className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all appearance-none"
                        >
                            <option value="">None</option>
                            {collections?.map(c => <option key={c._id} value={c.name}>{c.name}</option>)}
                        </select>
                    </div>
                    <div>
                        <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Stock Quantity</label>
                        <input
                            type="number"
                            min="0"
                            value={formData.stock}
                            onChange={(e) => setFormData({ ...formData, stock: e.target.value })}
                            className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all"
                            placeholder="0"
                        />
                    </div>
                </div>

                {error && (
                    <div className="p-3 md:p-4 bg-red-50 rounded-xl md:rounded-2xl flex items-center gap-2 md:gap-3 text-red-600 font-bold text-xs md:text-sm">
                        <AlertCircle size={18} md:size={20} />
                        {error}
                    </div>
                )}

                <div className="flex flex-col sm:flex-row justify-end gap-3 md:gap-4 pt-3 md:pt-4 border-t border-gray-50">
                    <Button variant="secondary" type="button" onClick={onCancel} className="w-full sm:w-auto h-12 md:h-14">
                        Cancel
                    </Button>
                    <Button
                        variant="primary"
                        type="submit"
                        loading={loading}
                        className="w-full sm:w-auto px-6 md:px-10 rounded-xl md:rounded-2xl h-12 md:h-14 text-sm md:text-base"
                    >
                        <Save size={18} md:size={20} className="mr-2" />
                        {product ? "Update Product" : "Save Product"}
                    </Button>
                </div>
            </form>
        </div>
    );
}

import React, { useState, useEffect } from "react";
import { useMutation, useQuery } from "convex/react";
import { api } from "../../../convex/_generated/api";
import { X, Save, Trash2, Image as ImageIcon, AlertCircle, Plus, Package } from "lucide-react";
import Button from "../../components/ui/Button";
import { useAdmin } from "../../context/AdminContext";

export default function ProductSetForm({ productSet, onSave, onCancel }) {
    const { adminToken } = useAdmin();
    const [formData, setFormData] = useState({
        name: "",
        description: "",
        products: [],
        specialPrice: "",
        image: "",
        badge: "",
        isActive: true,
    });

    const [imageFile, setImageFile] = useState(null);
    const [imagePreview, setImagePreview] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const generateUploadUrl = useMutation(api.products.generateUploadUrl);
    const addProductSet = useMutation(api.products.addProductSet);
    const updateProductSet = useMutation(api.products.updateProductSet);

    // Fetch all products for selection
    const products = useQuery(api.products.list) || [];

    useEffect(() => {
        if (productSet) {
            setFormData({
                name: productSet.name || "",
                description: productSet.description || "",
                products: productSet.products || [],
                specialPrice: productSet.specialPrice?.toString() || "",
                image: productSet.image || "",
                badge: productSet.badge || "",
                isActive: productSet.isActive !== false,
            });
            setImagePreview(productSet.image || "");
        }
    }, [productSet]);

    useEffect(() => {
        return () => {
            if (imagePreview && imagePreview.startsWith("blob:")) {
                URL.revokeObjectURL(imagePreview);
            }
        };
    }, [imagePreview]);

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            if (imagePreview && imagePreview.startsWith("blob:")) {
                URL.revokeObjectURL(imagePreview);
            }
            setImageFile(file);
            setImagePreview(URL.createObjectURL(file));
        }
    };

    const handleUpload = async (fileToUpload) => {
        if (!fileToUpload) return formData.image;
        const postUrl = await generateUploadUrl();
        const result = await fetch(postUrl, {
            method: "POST",
            headers: { "Content-Type": fileToUpload.type },
            body: fileToUpload,
        });
        const { storageId } = await result.json();
        return storageId;
    };

    const addProductToSet = (productId) => {
        if (!productId) return;
        const product = products.find(p => p._id === productId);
        if (!product) return;

        // Check if product already exists in set
        const exists = formData.products.find(p => p.productId === productId);
        if (exists) {
            setError("This product is already in the set");
            return;
        }

        setFormData({
            ...formData,
            products: [...formData.products, {
                productId,
                quantity: 1,
                selectedColor: null,
                selectedSize: null,
                selectedLogo: null,
            }]
        });
        setError("");
    };

    const removeProductFromSet = (index) => {
        setFormData({
            ...formData,
            products: formData.products.filter((_, i) => i !== index)
        });
    };

    const updateProductQuantity = (index, quantity) => {
        const updated = [...formData.products];
        updated[index] = { ...updated[index], quantity: Math.max(1, parseInt(quantity) || 1) };
        setFormData({ ...formData, products: updated });
    };

    const calculateOriginalPrice = () => {
        return formData.products.reduce((total, item) => {
            const product = products.find(p => p._id === item.productId);
            return total + (product?.price || 0) * item.quantity;
        }, 0);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        if (!formData.name.trim()) {
            setError("Please enter a name for the product set");
            setLoading(false);
            return;
        }

        if (formData.products.length < 2) {
            setError("Please add at least 2 products to create a bundle");
            setLoading(false);
            return;
        }

        if (!formData.specialPrice || parseFloat(formData.specialPrice) <= 0) {
            setError("Please enter a special price for the bundle");
            setLoading(false);
            return;
        }

        try {
            let finalImageUrl = formData.image;
            if (imageFile) {
                finalImageUrl = await handleUpload(imageFile);
            }

            const payloadProducts = formData.products.map(p => {
                const item = {
                    productId: p.productId,
                    quantity: p.quantity,
                };
                if (p.selectedColor) item.selectedColor = p.selectedColor;
                if (p.selectedSize) item.selectedSize = p.selectedSize;
                if (p.selectedLogo) item.selectedLogo = p.selectedLogo;
                return item;
            });

            const payload = {
                ...formData,
                products: payloadProducts,
                specialPrice: parseFloat(formData.specialPrice),
                image: finalImageUrl,
            };

            if (productSet) {
                await updateProductSet({ id: productSet._id, ...payload, adminToken });
            } else {
                await addProductSet({ ...payload, adminToken });
            }

            onSave();
        } catch (err) {
            setError("An error occurred while saving. Please try again.");
        } finally {
            setLoading(false);
        }
    };

    const originalPrice = calculateOriginalPrice();
    const savings = originalPrice - parseFloat(formData.specialPrice || 0);

    return (
        <div className="bg-white rounded-2xl md:rounded-[2rem] border border-gray-100 shadow-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-300 max-h-[90vh] overflow-y-auto">
            <div className="p-4 md:p-8 border-b border-gray-50 flex justify-between items-center sticky top-0 bg-white z-10">
                <div>
                    <h2 className="text-lg md:text-xl font-black text-brand-navy">
                        {productSet ? "Edit Product Bundle" : "Create Product Bundle"}
                    </h2>
                    <p className="text-[10px] md:text-xs text-gray-400 font-bold uppercase tracking-widest">
                        {productSet ? `Editing: ${productSet.name}` : "Create special bundles with discounted pricing"}
                    </p>
                </div>
                <button onClick={onCancel} className="p-2 hover:bg-gray-100 rounded-full transition-colors">
                    <X size={20} className="text-gray-400" />
                </button>
            </div>

            <form onSubmit={handleSubmit} className="p-4 md:p-8 space-y-6 md:space-y-8">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 md:gap-12">
                    <div className="space-y-4 md:space-y-6">
                        <div>
                            <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Bundle Name</label>
                            <input
                                type="text"
                                required
                                value={formData.name}
                                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all"
                                placeholder="e.g., Student Starter Pack"
                            />
                        </div>

                        <div>
                            <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Description</label>
                            <textarea
                                rows="3"
                                value={formData.description}
                                onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                                className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all resize-none"
                                placeholder="Describe what's included in this bundle..."
                            />
                        </div>

                        <div className="grid grid-cols-2 gap-3 md:gap-4">
                            <div>
                                <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Special Price (XOF)</label>
                                <input
                                    type="number"
                                    step="100"
                                    required
                                    value={formData.specialPrice}
                                    onChange={(e) => setFormData({ ...formData, specialPrice: e.target.value })}
                                    className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all"
                                    placeholder="8000"
                                />
                            </div>
                            <div>
                                <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Badge</label>
                                <input
                                    type="text"
                                    value={formData.badge}
                                    onChange={(e) => setFormData({ ...formData, badge: e.target.value })}
                                    className="w-full bg-gray-50 border-none rounded-xl md:rounded-2xl px-4 md:px-5 py-3 md:py-4 text-sm md:text-base text-brand-navy font-bold focus:ring-2 focus:ring-brand-orange/20 transition-all"
                                    placeholder="Best Value, etc."
                                />
                            </div>
                        </div>

                        {/* Price Preview */}
                        {formData.products.length > 0 && formData.specialPrice && (
                            <div className="bg-green-50 border border-green-100 rounded-xl p-4">
                                <div className="flex items-center justify-between mb-2">
                                    <span className="text-xs font-bold text-gray-500">Original Price:</span>
                                    <span className="text-sm font-bold text-gray-400 line-through">
                                        {originalPrice.toLocaleString()} XOF
                                    </span>
                                </div>
                                <div className="flex items-center justify-between">
                                    <span className="text-xs font-bold text-gray-500">Your Savings:</span>
                                    <span className="text-sm font-bold text-green-600">
                                        {savings > 0 ? `${savings.toLocaleString()} XOF` : "None"}
                                    </span>
                                </div>
                            </div>
                        )}
                    </div>

                    <div className="space-y-4 md:space-y-6">
                        <div>
                            <label className="block text-[10px] md:text-xs font-black uppercase tracking-widest text-gray-400 mb-2 ml-1">Bundle Image</label>
                            <div
                                className={`relative aspect-video rounded-2xl md:rounded-3xl overflow-hidden border-2 border-dashed transition-all flex flex-col items-center justify-center p-3 md:p-4 bg-gray-50 ${imagePreview ? "border-transparent" : "border-gray-200 hover:border-brand-orange/40"}`}
                            >
                                {imagePreview ? (
                                    <>
                                        <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
                                        <button
                                            type="button"
                                            onClick={() => { setImageFile(null); setImagePreview(""); setFormData({ ...formData, image: "" }) }}
                                            className="absolute top-2 md:top-4 right-2 md:right-4 bg-red-500 text-white p-1.5 md:p-2 rounded-lg md:rounded-xl shadow-lg hover:bg-red-600 transition-colors"
                                        >
                                            <Trash2 size={16} md:size={20} />
                                        </button>
                                    </>
                                ) : (
                                    <div className="text-center">
                                        <div className="inline-flex items-center justify-center w-12 h-12 md:w-16 md:h-16 rounded-full bg-white mb-3 md:mb-4 shadow-sm text-gray-400">
                                            <Package size={24} md:size={32} />
                                        </div>
                                        <p className="text-xs md:text-sm font-bold text-gray-500 mb-1">Click to upload bundle image</p>
                                        <p className="text-[8px] md:text-[10px] text-gray-400 font-bold uppercase tracking-widest">Optional</p>
                                    </div>
                                )}
                                <input
                                    type="file"
                                    accept="image/*"
                                    onChange={handleImageChange}
                                    className="absolute inset-0 opacity-0 cursor-pointer"
                                />
                            </div>
                        </div>

                        {/* Active Toggle */}
                        <div className="flex items-center justify-between bg-gray-50 rounded-xl p-4">
                            <span className="text-sm font-bold text-brand-navy">Active</span>
                            <button
                                type="button"
                                onClick={() => setFormData({ ...formData, isActive: !formData.isActive })}
                                className={`w-12 h-6 rounded-full transition-colors ${formData.isActive ? "bg-brand-orange" : "bg-gray-300"}`}
                            >
                                <div className={`w-5 h-5 bg-white rounded-full shadow transition-transform ${formData.isActive ? "translate-x-6" : "translate-x-0.5"}`} />
                            </button>
                        </div>
                    </div>
                </div>

                {/* Products Selection */}
                <div className="bg-gray-50 rounded-2xl md:rounded-3xl p-4 md:p-8">
                    <h3 className="font-black text-brand-navy mb-3 md:mb-4 text-sm md:text-base">Products in Bundle</h3>

                    {/* Add Product */}
                    <div className="flex gap-2 md:gap-3 mb-4 md:mb-6">
                        <select
                            onChange={(e) => addProductToSet(e.target.value)}
                            className="flex-1 bg-white border-none rounded-xl px-3 md:px-4 py-2.5 md:py-3 text-xs md:text-sm font-bold"
                            defaultValue=""
                        >
                            <option value="" disabled>Select a product to add...</option>
                            {products.map(p => (
                                <option key={p._id} value={p._id}>
                                    {p.name} - {p.price?.toLocaleString()} XOF
                                </option>
                            ))}
                        </select>
                    </div>

                    {/* Selected Products */}
                    {formData.products.length > 0 ? (
                        <div className="space-y-3">
                            {formData.products.map((item, index) => {
                                const product = products.find(p => p._id === item.productId);
                                return (
                                    <div key={index} className="flex items-center gap-3 bg-white px-3 py-2 rounded-xl shadow-sm">
                                        <div className="w-12 h-12 rounded-lg overflow-hidden bg-gray-100 flex-shrink-0">
                                            {product?.image && (
                                                <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                                            )}
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <p className="text-sm font-bold text-brand-navy truncate">{product?.name}</p>
                                            <p className="text-xs text-gray-400">{product?.price?.toLocaleString()} XOF each</p>
                                        </div>
                                        <div className="flex items-center gap-2">
                                            <span className="text-xs font-bold text-gray-400">Qty:</span>
                                            <input
                                                type="number"
                                                min="1"
                                                value={item.quantity}
                                                onChange={(e) => updateProductQuantity(index, e.target.value)}
                                                className="w-12 bg-gray-50 rounded-lg px-2 py-1 text-center text-sm font-bold"
                                            />
                                        </div>
                                        <button
                                            type="button"
                                            onClick={() => removeProductFromSet(index)}
                                            className="p-1.5 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                                        >
                                            <Trash2 size={16} />
                                        </button>
                                    </div>
                                );
                            })}
                        </div>
                    ) : (
                        <p className="text-sm text-gray-400 text-center py-4">No products added yet. Add at least 2 products to create a bundle.</p>
                    )}
                </div>

                {error && (
                    <div className="p-3 md:p-4 bg-red-50 rounded-xl md:rounded-2xl flex items-center gap-2 md:gap-3 text-red-600 font-bold text-xs md:text-sm">
                        <AlertCircle size={18} md:size={20} />
                        {error}
                    </div>
                )}

                <div className="flex flex-col sm:flex-row justify-end gap-3 md:gap-4 pt-3 md:pt-4 border-t border-gray-50">
                    <Button variant="secondary" type="button" onClick={onCancel} className="w-full sm:w-auto h-12 md:h-14">
                        Cancel
                    </Button>
                    <Button
                        variant="primary"
                        type="submit"
                        loading={loading}
                        className="w-full sm:w-auto px-6 md:px-10 rounded-xl md:rounded-2xl h-12 md:h-14 text-sm md:text-base"
                    >
                        <Save size={18} md:size={20} className="mr-2" />
                        {productSet ? "Update Bundle" : "Create Bundle"}
                    </Button>
                </div>
            </form>
        </div>
    );
}

import React, { useState } from "react";
import { useQuery, useMutation } from "convex/react";
import { api } from "../../../convex/_generated/api";
import { Plus, Package, Edit2, Trash2, Eye, EyeOff, Tag } from "lucide-react";
import Button from "../../components/ui/Button";
import { formatPrice } from "../../utils/format";
import ProductSetForm from "./ProductSetForm";
import { useAdmin } from "../../context/AdminContext";

export default function ProductSets() {
    const { adminToken } = useAdmin();
    const [showForm, setShowForm] = useState(false);
    const [editingSet, setEditingSet] = useState(null);

    const productSets = useQuery(api.products.listProductSets) || [];
    const removeProductSet = useMutation(api.products.removeProductSet);
    const toggleProductSet = useMutation(api.products.updateProductSet);

    const handleEdit = (set) => {
        setEditingSet(set);
        setShowForm(true);
    };

    const handleDelete = async (setId) => {
        if (window.confirm("Are you sure you want to delete this product bundle?")) {
            try {
                await removeProductSet({ id: setId, adminToken });
            } catch (err) {
                alert("Failed to delete product bundle");
            }
        }
    };

    const handleToggleActive = async (set) => {
        try {
            await toggleProductSet({
                id: set._id,
                isActive: !set.isActive,
                adminToken
            });
        } catch (err) {
            alert("Failed to update product bundle");
        }
    };

    const handleSave = () => {
        setShowForm(false);
        setEditingSet(null);
    };

    const handleCancel = () => {
        setShowForm(false);
        setEditingSet(null);
    };

    if (showForm) {
        return (
            <ProductSetForm
                productSet={editingSet}
                onSave={handleSave}
                onCancel={handleCancel}
            />
        );
    }

    return (
        <div className="p-6 md:p-8">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-8">
                <div>
                    <h1 className="text-2xl md:text-3xl font-black text-brand-navy">Product Bundles</h1>
                    <p className="text-sm text-gray-500 mt-1">Create special bundles with discounted pricing</p>
                </div>
                <Button
                    variant="primary"
                    onClick={() => setShowForm(true)}
                    className="flex items-center gap-2"
                >
                    <Plus size={18} />
                    Create Bundle
                </Button>
            </div>

            {productSets.length === 0 ? (
                <div className="text-center py-16 bg-gray-50 rounded-3xl">
                    <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-gray-100 mb-4">
                        <Package className="h-8 w-8 text-gray-400" />
                    </div>
                    <h3 className="text-lg font-bold text-gray-900 mb-2">No product bundles yet</h3>
                    <p className="text-gray-500 mb-6 max-w-sm mx-auto">Create special bundles to offer discounted pricing on product combinations.</p>
                    <Button variant="primary" onClick={() => setShowForm(true)}>
                        Create Your First Bundle
                    </Button>
                </div>
            ) : (
                <div className="grid gap-4">
                    {productSets.map((set) => (
                        <div
                            key={set._id}
                            className={`bg-white rounded-2xl p-6 border transition-all ${
                                set.isActive 
                                    ? "border-gray-100 shadow-sm" 
                                    : "border-gray-200 bg-gray-50"
                            }`}
                        >
                            <div className="flex flex-col md:flex-row md:items-center gap-4">
                                {/* Image */}
                                <div className="w-full md:w-24 h-24 rounded-xl overflow-hidden bg-gray-100 flex-shrink-0">
                                    {set.image ? (
                                        <img src={set.image} alt={set.name} className="w-full h-full object-cover" />
                                    ) : (
                                        <div className="w-full h-full grid grid-cols-2 gap-0.5 p-1">
                                            {set.products?.slice(0, 4).map((p, idx) => (
                                                <div key={idx} className="rounded bg-gray-200">
                                                    {p.productImage && (
                                                        <img src={p.productImage} alt="" className="w-full h-full object-cover" />
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>

                                {/* Info */}
                                <div className="flex-1">
                                    <div className="flex items-center gap-2 mb-1">
                                        <h3 className="text-lg font-black text-brand-navy">{set.name}</h3>
                                        {set.badge && (
                                            <span className="text-xs font-bold text-white bg-brand-orange px-2 py-0.5 rounded-full">
                                                {set.badge}
                                            </span>
                                        )}
                                        {!set.isActive && (
                                            <span className="text-xs font-bold text-gray-500 bg-gray-200 px-2 py-0.5 rounded-full flex items-center gap-1">
                                                <EyeOff size={10} /> Inactive
                                            </span>
                                        )}
                                    </div>
                                    <p className="text-sm text-gray-500 mb-2 line-clamp-1">
                                        {set.description || "No description"}
                                    </p>
                                    <div className="flex flex-wrap items-center gap-3 text-sm">
                                        <span className="font-bold text-gray-400">
                                            {set.products?.length || 0} products
                                        </span>
                                        <span className="text-gray-300">|</span>
                                        <span className="font-bold text-gray-400">
                                            Original: <span className="line-through">{formatPrice(set.originalPrice)}</span>
                                        </span>
                                        <span className="text-gray-300">|</span>
                                        <span className="font-black text-brand-navy">
                                            Bundle: {formatPrice(set.specialPrice)}
                                        </span>
                                        {set.savings > 0 && (
                                            <>
                                                <span className="text-gray-300">|</span>
                                                <span className="font-bold text-green-600 flex items-center gap-1">
                                                    <Tag size={14} />
                                                    Save {formatPrice(set.savings)}
                                                </span>
                                            </>
                                        )}
                                    </div>
                                </div>

                                {/* Products Preview */}
                                <div className="hidden lg:flex items-center gap-2 flex-shrink-0">
                                    {set.products?.slice(0, 3).map((p, idx) => (
                                        <div key={idx} className="w-10 h-10 rounded-lg overflow-hidden bg-gray-100">
                                            {p.productImage && (
                                                <img src={p.productImage} alt="" className="w-full h-full object-cover" />
                                            )}
                                        </div>
                                    ))}
                                    {set.products?.length > 3 && (
                                        <span className="text-xs font-bold text-gray-400">+{set.products.length - 3}</span>
                                    )}
                                </div>

                                {/* Actions */}
                                <div className="flex items-center gap-2 flex-shrink-0">
                                    <button
                                        onClick={() => handleToggleActive(set)}
                                        className={`p-2 rounded-xl transition-colors ${
                                            set.isActive 
                                                ? "text-gray-400 hover:text-brand-orange hover:bg-orange-50" 
                                                : "text-green-600 hover:bg-green-50"
                                        }`}
                                        title={set.isActive ? "Deactivate" : "Activate"}
                                    >
                                        {set.isActive ? <EyeOff size={18} /> : <Eye size={18} />}
                                    </button>
                                    <button
                                        onClick={() => handleEdit(set)}
                                        className="p-2 text-gray-400 hover:text-brand-orange hover:bg-orange-50 rounded-xl transition-colors"
                                        title="Edit"
                                    >
                                        <Edit2 size={18} />
                                    </button>
                                    <button
                                        onClick={() => handleDelete(set._id)}
                                        className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors"
                                        title="Delete"
                                    >
                                        <Trash2 size={18} />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
}

import React, { useState } from "react";
import { Link } from "react-router-dom";
import { useQuery, useMutation } from "convex/react";
import { api } from "../../../convex/_generated/api";
import {
    Edit2,
    Trash2,
    Plus,
    Search,
    ExternalLink,
    MoreVertical,
    Filter,
    Package,
    AlertCircle
} from "lucide-react";
import Button from "../../components/ui/Button";
import LoadingSpinner from "../../components/ui/LoadingSpinner";
import { formatPrice } from "../../utils/format.js";
import { useAdmin } from "../../context/AdminContext";

import AdminProductForm from "./ProductForm";

export default function AdminProducts() {
    const { adminToken } = useAdmin();
    const products = useQuery(api.products.list);
    const removeProduct = useMutation(api.products.removeProduct);
    const [searchTerm, setSearchTerm] = useState("");
    const [filterCategory, setFilterCategory] = useState("All");
    const [isFormOpen, setIsFormOpen] = useState(false);
    const [editingProduct, setEditingProduct] = useState(null);

    const isLoading = products === undefined;

    const filteredProducts = products?.filter(p => {
        const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = filterCategory === "All" || p.category === filterCategory;
        return matchesSearch && matchesCategory;
    }) || [];

    const categories = ["All", ...new Set(products?.map(p => p.category) || [])];

    const handleDelete = async (id) => {
        if (window.confirm("Are you sure you want to delete this product? This action cannot be undone.")) {
            try {
                await removeProduct({ id, adminToken });
            } catch (err) {
                alert("Failed to delete product. Please try again.");
            }
        }
    };

    const handleEdit = (product) => {
        setEditingProduct(product);
        setIsFormOpen(true);
    };

    const handleAdd = () => {
        setEditingProduct(null);
        setIsFormOpen(true);
    };

    const handleFormSave = () => {
        setIsFormOpen(false);
        setEditingProduct(null);
    };

    if (isLoading) {
        return (
            <div className="h-full flex flex-col items-center justify-center space-y-4">
                <LoadingSpinner size="lg" />
                <p className="text-gray-400 font-bold uppercase tracking-widest text-xs">Loading Catalog...</p>
            </div>
        );
    }

    if (isFormOpen) {
        return (
            <AdminProductForm
                product={editingProduct}
                onSave={handleFormSave}
                onCancel={() => setIsFormOpen(false)}
            />
        );
    }

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            {/* Action Bar */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div className="flex-1 w-full md:max-w-md relative">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 h-5 w-5" />
                    <input
                        type="text"
                        placeholder="Search products..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full bg-white border border-gray-100 rounded-2xl pl-12 pr-4 py-3 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-brand-orange/20 transition-all shadow-sm"
                    />
                </div>

                <div className="flex items-center gap-3 w-full md:w-auto">
                    <div className="relative inline-block">
                        <select
                            value={filterCategory}
                            onChange={(e) => setFilterCategory(e.target.value)}
                            className="appearance-none bg-white border border-gray-100 rounded-2xl px-5 py-3 pr-10 text-xs font-bold font-black uppercase tracking-widest text-brand-navy focus:outline-none focus:ring-2 focus:ring-brand-orange/20 shadow-sm cursor-pointer"
                        >
                            {categories.map(c => <option key={c} value={c}>{c}</option>)}
                        </select>
                        <Filter className="absolute right-4 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-gray-400 pointer-events-none" />
                    </div>

                    <Button variant="primary" onClick={handleAdd} className="rounded-2xl h-12 px-6 flex-shrink-0">
                        <Plus size={18} className="mr-2" />
                        Add Product
                    </Button>
                </div>
            </div>

            {/* Product List */}
            <div className="bg-white rounded-[2rem] border border-gray-100 shadow-sm overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left">
                        <thead>
                            <tr className="bg-gray-50/50 border-b border-gray-50/50">
                                <th className="px-8 py-5 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">Product</th>
                                <th className="px-8 py-5 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400 md:table-cell hidden">Category</th>
                                <th className="px-8 py-5 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">Price</th>
                                <th className="px-8 py-5 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">Stock</th>
                                <th className="px-8 py-5 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400 lg:table-cell hidden">Rating</th>
                                <th className="px-8 py-5 text-[10px] font-black uppercase tracking-[0.2em] text-gray-400 text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-50">
                            {filteredProducts.map((p) => (
                                <tr key={p._id} className="hover:bg-gray-50/30 transition-colors group">
                                    <td className="px-8 py-6">
                                        <div className="flex items-center gap-4">
                                            <div className="w-12 h-16 bg-gray-50 rounded-lg overflow-hidden flex-shrink-0">
                                                <img src={p.image} alt={p.name} className="w-full h-full object-cover" />
                                            </div>
                                            <div>
                                                <p className="font-black text-brand-navy text-sm group-hover:text-brand-orange transition-colors">{p.name}</p>
                                                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">ID: {p._id.substring(0, 8)}...</p>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-8 py-6 md:table-cell hidden">
                                        <span className="text-[10px] font-black uppercase tracking-widest text-gray-500 bg-gray-100 px-3 py-1 rounded-full">
                                            {p.category}
                                        </span>
                                    </td>
                                    <td className="px-8 py-6">
                                        <p className="font-black text-brand-navy text-sm">{formatPrice(p.price)}</p>
                                    </td>
                                    <td className="px-8 py-6">
                                        <div className="flex flex-col gap-1">
                                            <span className={`text-xs font-bold ${p.stock === 0 ? "text-red-500" : p.stock <= 5 ? "text-orange-500" : "text-green-500"}`}>
                                                {p.stock === 0 ? "Sold Out" : `${p.stock} units`}
                                            </span>
                                            {p.stock <= 5 && p.stock > 0 && (
                                                <span className="text-[8px] font-black uppercase tracking-widest text-orange-400">Low Stock</span>
                                            )}
                                        </div>
                                    </td>
                                    <td className="px-8 py-6 lg:table-cell hidden">
                                        <div className="flex items-center gap-1">
                                            <span className="text-sm font-bold text-gray-700">{p.rating}</span>
                                            <span className="text-yellow-400 text-xs">Γÿà</span>
                                        </div>
                                    </td>
                                    <td className="px-8 py-6 text-right">
                                        <div className="flex items-center justify-end gap-2">
                                            <button
                                                onClick={() => handleEdit(p)}
                                                className="p-2 text-gray-400 hover:text-brand-orange hover:bg-brand-orange/5 rounded-lg transition-all"
                                                title="Edit Product"
                                            >
                                                <Edit2 size={18} />
                                            </button>
                                            <button
                                                onClick={() => handleDelete(p._id)}
                                                className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
                                                title="Delete Product"
                                            >
                                                <Trash2 size={18} />
                                            </button>
                                            <Link to={`/product/${p._id}`} target="_blank" className="p-2 text-gray-400 hover:text-brand-navy hover:bg-gray-100 rounded-lg transition-all" title="View in Store">
                                                <ExternalLink size={18} />
                                            </Link>
                                        </div>
                                    </td>
                                </tr>
                            ))}


                            {filteredProducts.length === 0 && (
                                <tr>
                                    <td colSpan="5" className="px-8 py-32 text-center">
                                        <div className="flex flex-col items-center">
                                            <div className="w-16 h-16 rounded-full bg-gray-50 flex items-center justify-center mb-6">
                                                <Package className="h-8 w-8 text-gray-200" />
                                            </div>
                                            <h3 className="font-black text-brand-navy text-lg mb-2">No Products Found</h3>
                                            <p className="text-gray-400 text-sm max-w-xs mx-auto mb-8 font-medium">Try adjusting your search criteria or add a new product to the catalog.</p>
                                            <Button variant="secondary" onClick={() => { setSearchTerm(""); setFilterCategory("All"); }}>
                                                Clear Filters
                                            </Button>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}
